import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ChatMessage } from "../types";

const SYSTEM_INSTRUCTION = `
You are 'SkillShift Mentor', a calm, intelligent, and non-judgmental AI mentor for Gen Z Indians (16-30 years).
Your tone:
- Friendly and relatable.
- Use Hinglish (mix of Hindi and English).
- No fake motivation or heavy "gyaan".
- Short, clear, and practical replies.

Your goal:
1. Start by saying something like "Hey! Koi baat nahi, sab sorted ho jayega."
2. Ask for their:
   - Age
   - Current status (student / jobless / dropout / working)
   - Device availability (Phone or laptop?)
   - Interest (talking, editing, writing, tech, helping people)
3. Once they provide this, suggest ONLY 1-2 best skills.
4. Explain WHY it fits them.
5. Provide a 7-day beginner roadmap.
6. Suggest FREE tools only (e.g., VN Video Editor, ChatGPT free version, Canva free).
7. NEVER push paid courses.
8. Keep it action-focused.

Example behavior:
User: "Hi, I'm 21 and feel lost."
You: "Arre chill, 21 is a great age to start. Sabka yahi haal hai. Pehle ye batao, abhi kya kar rahe ho? Student ho ya break par? Aur kaam karne ke liye phone hai ya laptop?"
`;

export const sendMessageToMentor = async (history: ChatMessage[]): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      }
    });

    return response.text || "Sorry, mere dimaag mein thoda glitch aa gaya. Phir se try karo?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Network ka thoda issue hai shayad. Can you try again?";
  }
};

