              className="glass-card p-5 rounded-2xl border border-slate-800 flex flex-col items-start gap-2 hover:border-slate-700 transition-all text-left"
            >
              <div className="w-full flex justify-between items-center">
                <span className="text-sm font-bold text-slate-100">{skill.title}</span>
                <Icons.ArrowRight />
              </div>
              <p className="text-xs text-slate-400 line-clamp-1">{skill.description}</p>
              <div className="flex gap-2 mt-2">
                <span className="bg-blue-500/10 text-blue-400 text-[10px] px-2 py-0.5 rounded-full border border-blue-500/20">
                  {skill.difficulty}
                </span>
                <span className="bg-slate-800 text-slate-400 text-[10px] px-2 py-0.5 rounded-full border border-slate-700">
                  {skill.timeToStart}
                </span>
              </div>
