export default Roadmaps;

import React, { useState, useEffect } from 'react';
import { Page } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    // Basic splash screen timeout
    const timer = setTimeout(() => setIsLoaded(true), 1200);
    return () => clearTimeout(timer);
  }, []);

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={setCurrentPage} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return <Roadmaps />;
      case Page.BOOST:
        return <DailyBoost />;
      default:
        return <Home onNavigate={setCurrentPage} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <div className="relative">
          <div className="w-20 h-20 rounded-3xl bg-gradient-to-tr from-blue-600 to-pink-600 animate-spin transition-all duration-[2000ms]"></div>
          <div className="absolute inset-0 flex items-center justify-center text-white font-bold text-2xl font-heading">S</div>
        </div>
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-2xl font-bold font-heading text-white">SkillShift</h1>
          <p className="text-slate-500 text-xs tracking-widest uppercase">Initializing Mentor...</p>
        </div>
      </div>
    );
  }

  return (
    <Layout currentPage={currentPage} onPageChange={setCurrentPage}>
      {renderPage()}
    </Layout>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Page {
