const SYSTEM_INSTRUCTION = `
You are “SkillShift AI Mentor”.
Your role is to guide confused Gen Z users (16–30) calmly and practically.
You are not a motivational speaker. You are a clear-thinking mentor.

RULES:
- Use simple Hindi + English mix (Hinglish).
- Keep replies short and actionable.
- No judgement, no pressure.
- No fake earning promises.
- Avoid complex terms.
- One step at a time.

PROCESS:
1) If the conversation just started, your first message should be: “Main yahin hoon. Bas apni situation likho. Hum ek clear next step nikaalte hain.” (Note: This is usually handled by the UI, but keep it in mind for context).
2) Ask these questions (one by one or in a small group if natural):
   - Age?
   - Student / Jobless / Working / Dropout?
   - Phone or Laptop?
   - Interest: editing, writing, talking, tech, helping people?
3) Based on their answers, suggest ONLY 1–2 best skills from these categories: 
   - Mobile Video Editing (if phone only, creative)
   - Ghost Writing (if likes writing, tech-savvy)
   - Prompt Engineering (if likes AI, tech)
   - Social Media Manager (if likes talking, management)
4) Explain WHY this skill fits the user.
5) Give a 7-day beginner plan based on the suggested skill.
6) Recommend only FREE tools (CapCut, VN, Google Docs, ChatGPT, etc.).
7) Map the user to one of the roadmaps available in the app.

TONE:
Calm. Friendly. Honest. Like an elder brother/sister who actually understands.

END EACH CHAT SESSION (when a plan is given) WITH:
“Aaj ka chhota task ye raha. [Insert specific task here]. Kal yahin se continue karenge.”
`;

export const sendMessageToMentor = async (history: ChatMessage[]): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      }
    });

    return response.text || "Sorry, mere dimaag mein thoda glitch aa gaya. Phir se try karo?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Network ka thoda issue hai shayad. Can you try again?";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { sendMessageToMentor } from '../services/geminiService';
import { Icons } from '../constants';

const MentorChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Main yahin hoon. Bas apni situation likho. Hum ek clear next step nikaalte hain.' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMessage: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setLoading(true);

    const responseText = await sendMessageToMentor([...messages, userMessage]);

    setMessages(prev => [...prev, { role: 'model', text: responseText }]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-180px)]">
      {/* Messages Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto flex flex-col gap-4 p-2 scroll-smooth"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fadeIn`}
          >
            <div 
              className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'glass-card text-slate-200 rounded-tl-none border-pink-500/20 shadow-lg'
              }`}
            >
              {msg.text.split('\n').map((line, i) => (
                <p key={i} className={line.trim() === '' ? 'h-2' : 'mb-1'}>
                  {line}
                </p>
              ))}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start animate-pulse">
            <div className="glass-card p-4 rounded-2xl rounded-tl-none flex gap-1">
              <div className="w-1.5 h-1.5 rounded-full bg-slate-500 animate-bounce"></div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-500 animate-bounce delay-100"></div>
              <div className="w-1.5 h-1.5 rounded-full bg-slate-500 animate-bounce delay-200"></div>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="mt-4 flex gap-2 items-end">
        <textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Yahan type karo..."
          rows={1}
          className="flex-1 bg-slate-900 border border-slate-700 rounded-2xl px-4 py-3 text-sm focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 resize-none max-h-32 transition-all"
          onKeyDown={(e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleSend();
            }
          }}
        />
        <button
          onClick={handleSend}
          disabled={loading || !input.trim()}
          className={`p-3.5 rounded-2xl transition-all ${
            loading || !input.trim() 
              ? 'bg-slate-800 text-slate-500' 
              : 'bg-blue-600 text-white neon-glow-blue'
          }`}
        >
          <Icons.ArrowRight />
        </button>
      </div>
    </div>
  );
};

