export const sendMessageToMentor = async (history: ChatMessage[]): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const contents = history.map(msg => ({
      role: msg.role === 'user' ? 'user' : 'model',
      parts: [{ text: msg.text }]
    }));

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: contents,
      config: {
        systemInstruction: MENTOR_SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });

    return response.text || "Sorry, glitch in the matrix. Try again?";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Network issue. Refresh karlo?";
  }
};

export const generateDetailedRoadmap = async (profile: any): Promise<any> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const prompt = `User profile data: ${JSON.stringify(profile)}. Generate full 30-day roadmap JSON now.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: ROADMAP_ENGINE_INSTRUCTION,
        responseMimeType: "application/json",
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Roadmap Engine Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Icons } from '../constants';
import { generateDetailedRoadmap } from '../services/geminiService';

enum EngineState {
  INTRO,
  QUESTIONNAIRE,
  GENERATING,
  PREVIEW
}

const QUESTIONS = [
  { key: 'age', text: "Pehle apni age batao? (e.g. 21)" },
  { key: 'status', text: "Abhi kya kar rahe ho? (Student / Jobless / Working / Dropout)" },
  { key: 'device', text: "Kaam ke liye kya device hai? (Only Phone / Laptop / Both)" },
  { key: 'interest', text: "Kis cheez mein thoda interest hai? (Editing / Writing / AI / Social Media / Unsure)" },
  { key: 'goal', text: "Main goal kya hai? (Skill seekhna / First earning / Freelancing / Confidence)" }
];

const Roadmaps: React.FC = () => {
  const [state, setState] = useState<EngineState>(EngineState.INTRO);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [inputValue, setInputValue] = useState('');
  const [generatedData, setGeneratedData] = useState<any>(null);
  const [chatHistory, setChatHistory] = useState<{ role: 'ai' | 'user', text: string }[]>([]);
  const [generationStep, setGenerationStep] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);

  const steps = [
    "Skill select ho raha hai...",
    "Daily plan ban raha hai...",
    "PDF content generate ho raha hai...",
    "Earning guide finalize ho rahi hai...",
