enum EngineState {
  INTRO,
  QUESTIONNAIRE,
  GENERATING,
  PREVIEW
}

const QUESTIONS = [
  { key: 'age', text: "Pehle apni age batao? (e.g. 21)" },
  { key: 'status', text: "Abhi kya kar rahe ho? (Student / Jobless / Working / Dropout)" },
  { key: 'device', text: "Kaam ke liye kya device hai? (Only Phone / Laptop / Both)" },
  { key: 'interest', text: "Kis cheez mein thoda interest hai? (Editing / Writing / AI / Social Media / Unsure)" },
  { key: 'goal', text: "Main goal kya hai? (Skill seekhna / First earning / Freelancing / Confidence)" }
];

const AICore = ({ size = "w-24 h-24" }: { size?: string }) => (
  <div className={`relative ${size}`}>
    <div className="absolute inset-0 rounded-full border border-blue-500/10 animate-spin-slow"></div>
    <div className="absolute inset-2 rounded-full border border-pink-500/10 animate-spin-reverse-slow"></div>
    <div className="absolute inset-6 rounded-full bg-gradient-to-br from-blue-600/20 via-purple-600/30 to-pink-600/20 blur-md animate-pulse"></div>
    <div className="absolute inset-8 rounded-full bg-blue-500/40 blur-sm"></div>
    <div className="absolute inset-10 rounded-full bg-white/10"></div>
  </div>
);

const Roadmaps: React.FC = () => {
  const [state, setState] = useState<EngineState>(EngineState.INTRO);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [inputValue, setInputValue] = useState('');
  const [generatedData, setGeneratedData] = useState<any>(null);
  const [chatHistory, setChatHistory] = useState<{ role: 'ai' | 'user', text: string }[]>([]);
  const [generationStep, setGenerationStep] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);

  const steps = [
    "Skill pool se best choice ho rahi hai...",
    "30-day detailed plan ban raha hai...",
    "Daily tasks and checklists ready ho rahi hain...",
    "Earning guide customize ho rahi hai...",
    "Bas roadmap finalize ho raha hai..."
  ];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatHistory, state]);

  useEffect(() => {
    let interval: any;
    if (state === EngineState.GENERATING) {
      interval = setInterval(() => {
        setGenerationStep(prev => (prev < steps.length - 1 ? prev + 1 : prev));
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [state]);

  const startEngine = () => {
    setState(EngineState.QUESTIONNAIRE);
    setChatHistory([{ role: 'ai', text: QUESTIONS[0].text }]);
  };

  const handleAnswer = async () => {
    if (!inputValue.trim()) return;

    const currentKey = QUESTIONS[currentQuestionIndex].key;
    const newAnswers = { ...answers, [currentKey]: inputValue };
    setAnswers(newAnswers);

    const newHistory = [...chatHistory, { role: 'user' as const, text: inputValue }];
    setChatHistory(newHistory);
    setInputValue('');

    if (currentQuestionIndex < QUESTIONS.length - 1) {
      const nextIndex = currentQuestionIndex + 1;
      setCurrentQuestionIndex(nextIndex);
      setTimeout(() => {
        setChatHistory(prev => [...prev, { role: 'ai', text: QUESTIONS[nextIndex].text }]);
      }, 500);
    } else {
      setState(EngineState.GENERATING);
      setGenerationStep(0);
      const roadmap = await generateDetailedRoadmap(newAnswers);
      if (roadmap) {
        setGeneratedData(roadmap);
        setState(EngineState.PREVIEW);
      } else {
        alert("Something went wrong. Please try again.");
        setState(EngineState.INTRO);
      }
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (state === EngineState.INTRO) {
    return (
      <div className="flex flex-col gap-8 animate-fadeIn py-6">
        <div className="flex flex-col gap-4 text-center">
          <div className="mx-auto w-16 h-16 rounded-3xl bg-blue-600/20 flex items-center justify-center text-blue-500 mb-2">
            <Icons.Map />
          </div>
          <h2 className="text-3xl font-bold font-heading">Roadmap Engine</h2>
          <p className="text-slate-400 text-sm leading-relaxed">
            Confused ho? Apna custom roadmap banao. <br/>
            No login, no gyaan. 20 potential skills mein se best choose karenge.
          </p>
        </div>

        <button 
          onClick={startEngine}
          className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all"
        >
          <span>Start My Roadmap</span>
          <Icons.ArrowRight />
        </button>

        <div className="grid grid-cols-2 gap-4 mt-8">
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">🔍</div>
              <div className="text-[10px] font-bold text-slate-300">20+ Skills Pool</div>
           </div>
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">📄</div>
              <div className="text-[10px] font-bold text-slate-300">Custom PDF</div>
           </div>
        </div>
      </div>
    );
  }

  if (state === EngineState.QUESTIONNAIRE) {
    return (
      <div className="flex flex-col h-[calc(100vh-200px)]">
        <div className="flex items-center gap-2 mb-4 text-slate-500">
           <button onClick={() => setState(EngineState.INTRO)} className="p-1"><div className="rotate-180"><Icons.ArrowRight /></div></button>
           <span className="text-xs font-bold uppercase tracking-wider">Step {currentQuestionIndex + 1} of 5</span>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fadeIn`}>
              <div className={`max-w-[85%] p-4 rounded-2xl text-sm ${
                msg.role === 'user' ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' : 'glass-card border-slate-800 text-slate-200 rounded-tl-none shadow-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-4 flex gap-2">
          <input 
            type="text" 
            autoFocus
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAnswer()}
            placeholder="Type your answer..."
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-blue-500 transition-all text-white"
          />
          <button 
            onClick={handleAnswer}
            className="p-3 bg-blue-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"
          >
            <Icons.ArrowRight />
          </button>
        </div>
      </div>
    );
  }

  if (state === EngineState.GENERATING) {
    return (
      <div className="flex flex-col items-center justify-center h-[calc(100vh-200px)] gap-10">
        <AICore size="w-32 h-32" />
        <div className="text-center space-y-4">
          <h3 className="text-2xl font-bold text-white font-heading">Processing Potential...</h3>
          <div className="space-y-2">
