);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsLoaded(true), 1200);
    return () => clearTimeout(timer);
  }, []);

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={setCurrentPage} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return <Roadmaps />;
      case Page.BOOST:
        return <DailyBoost />;
      default:
        return <Home onNavigate={setCurrentPage} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-2xl font-semibold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <p className="text-slate-500 text-[10px] tracking-[0.2em] uppercase font-medium animate-pulse">Initializing</p>
        </div>
      </div>
    );
  }

  return (
    <Layout currentPage={currentPage} onPageChange={setCurrentPage}>
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Icons } from '../constants';
import { generateDetailedRoadmap } from '../services/geminiService';
import { ProgressRing } from '../App';

enum EngineState {
  INTRO,
  QUESTIONNAIRE,
  GENERATING,
  PREVIEW
}

const QUESTIONS = [
  { key: 'age', text: "Pehle apni age batao? (e.g. 21)" },
  { key: 'status', text: "Abhi kya kar rahe ho? (Student / Jobless / Working / Dropout)" },
  { key: 'device', text: "Kaam ke liye kya device hai? (Only Phone / Laptop / Both)" },
  { key: 'interest', text: "Kis cheez mein thoda interest hai? (Editing / Writing / AI / Social Media / Unsure)" },
  { key: 'goal', text: "Main goal kya hai? (Skill seekhna / First earning / Freelancing / Confidence)" }
];

const Roadmaps: React.FC = () => {
  const [state, setState] = useState<EngineState>(EngineState.INTRO);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [inputValue, setInputValue] = useState('');
  const [generatedData, setGeneratedData] = useState<any>(null);
  const [chatHistory, setChatHistory] = useState<{ role: 'ai' | 'user', text: string }[]>([]);
  const [generationStep, setGenerationStep] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);

  const steps = [
    "Analyzing profile data",
    "Mapping skills to interests",
    "Crafting 30-day curriculum",
    "Configuring earning modules",
    "Finalizing custom roadmap"
  ];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatHistory, state]);

  useEffect(() => {
    let interval: any;
    if (state === EngineState.GENERATING) {
      interval = setInterval(() => {
        setGenerationStep(prev => (prev < steps.length - 1 ? prev + 1 : prev));
      }, 1800);
    }
    return () => clearInterval(interval);
  }, [state]);

  const startEngine = () => {
    setState(EngineState.QUESTIONNAIRE);
    setChatHistory([{ role: 'ai', text: QUESTIONS[0].text }]);
  };

  const handleAnswer = async () => {
    if (!inputValue.trim()) return;

    const currentKey = QUESTIONS[currentQuestionIndex].key;
    const newAnswers = { ...answers, [currentKey]: inputValue };
    setAnswers(newAnswers);

    const newHistory = [...chatHistory, { role: 'user' as const, text: inputValue }];
    setChatHistory(newHistory);
    setInputValue('');

    if (currentQuestionIndex < QUESTIONS.length - 1) {
      const nextIndex = currentQuestionIndex + 1;
      setCurrentQuestionIndex(nextIndex);
      setTimeout(() => {
        setChatHistory(prev => [...prev, { role: 'ai', text: QUESTIONS[nextIndex].text }]);
      }, 400);
    } else {
      setState(EngineState.GENERATING);
      setGenerationStep(0);
      const roadmap = await generateDetailedRoadmap(newAnswers);
      if (roadmap) {
        setGeneratedData(roadmap);
        setState(EngineState.PREVIEW);
      } else {
        alert("Something went wrong. Please try again.");
        setState(EngineState.INTRO);
      }
    }
  };

  const handlePrint = () => {
    window.print();
  };

  if (state === EngineState.INTRO) {
    return (
      <div className="flex flex-col gap-8 animate-fadeIn py-6">
        <div className="flex flex-col gap-4 text-center">
          <div className="mx-auto w-16 h-16 rounded-3xl bg-blue-600/10 flex items-center justify-center text-blue-500 mb-2">
            <Icons.Map />
          </div>
          <h2 className="text-3xl font-bold font-heading">Roadmap Engine</h2>
          <p className="text-slate-400 text-sm leading-relaxed">
            Confused ho? Apna custom roadmap banao. <br/>
            No login, no gyaan. Just a clear path to follow.
          </p>
        </div>

        <button 
          onClick={startEngine}
          className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all"
        >
          <span>Start My Roadmap</span>
          <Icons.ArrowRight />
        </button>

        <div className="grid grid-cols-2 gap-4 mt-8">
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">🎯</div>
              <div className="text-[10px] font-bold text-slate-300">Personalized</div>
           </div>
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">📄</div>
              <div className="text-[10px] font-bold text-slate-300">Save as PDF</div>
           </div>
        </div>
      </div>
    );
  }

  if (state === EngineState.QUESTIONNAIRE) {
    return (
      <div className="flex flex-col h-[calc(100vh-200px)]">
        <div className="flex items-center gap-2 mb-4 text-slate-500">
           <button onClick={() => setState(EngineState.INTRO)} className="p-1"><div className="rotate-180"><Icons.ArrowRight /></div></button>
           <span className="text-xs font-bold uppercase tracking-wider">Step {currentQuestionIndex + 1} of 5</span>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fadeIn`}>
              <div className={`max-w-[85%] p-4 rounded-2xl text-sm ${
                msg.role === 'user' ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' : 'glass-card border-slate-800 text-slate-200 rounded-tl-none shadow-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-4 flex gap-2">
          <input 
            type="text" 
            autoFocus
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAnswer()}
            placeholder="Type your answer..."
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-blue-500 transition-all text-white"
          />
          <button 
            onClick={handleAnswer}
            className="p-3 bg-blue-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"
          >
            <Icons.ArrowRight />
          </button>
        </div>
      </div>
    );
  }

  if (state === EngineState.GENERATING) {
    return (
      <div className="flex flex-col items-center justify-center h-[calc(100vh-200px)] gap-10">
        <ProgressRing size="w-16 h-16" />
        <div className="text-center space-y-6">
          <h3 className="text-xl font-semibold text-white font-heading opacity-90 tracking-tight">Designing Roadmap</h3>
          <div className="flex flex-col gap-2">
            {steps.map((step, idx) => (
              <p key={idx} className={`text-[11px] uppercase tracking-widest font-medium transition-all duration-500 ${idx === generationStep ? 'text-blue-400' : idx < generationStep ? 'text-slate-500' : 'text-slate-800'}`}>
                {step}
              </p>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (state === EngineState.PREVIEW && generatedData) {
    return (
      <div className="flex flex-col gap-6 animate-fadeIn pb-24">
        <div className="no-print flex items-center justify-between sticky top-20 z-40 bg-slate-950/90 backdrop-blur-md py-3 px-1 rounded-xl">
           <button onClick={() => setState(EngineState.INTRO)} className="flex items-center gap-2 text-slate-500 text-xs font-bold uppercase tracking-widest"><div className="rotate-180 scale-75"><Icons.ArrowRight /></div> Reset</button>
           <button onClick={handlePrint} className="px-6 py-3 bg-pink-600 text-white rounded-xl text-xs font-bold flex items-center gap-2 shadow-xl neon-glow-pink active:scale-95 transition-all"><Icons.Zap /> Download Custom PDF</button>
        </div>

        <div className="print-area glass-card rounded-[2.5rem] p-8 border-blue-500/20 print:bg-white print:text-black print:p-12 print:border-none print:shadow-none print:max-w-none">
           {/* Cover Page Logic */}
           <div className="mb-16 text-center border-b border-slate-800 print:border-gray-200 pb-12">
              <h1 className="text-4xl font-bold font-heading mb-3 text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-pink-500 print:text-black print:bg-none print:text-5xl uppercase tracking-tighter">
                {generatedData.skillName}
              </h1>
