              <div className="p-6 bg-slate-900/50 rounded-3xl border border-slate-800 text-left print:bg-gray-50 print:border-gray-300">
                <div className="flex flex-col gap-4">
                  <div>
                    <span className="text-[10px] font-bold text-blue-500 uppercase tracking-[0.2em] block mb-2">Goal: {generatedData.userGoal}</span>
