                       <div className="my-12 p-8 rounded-3xl bg-blue-600/5 border border-blue-500/20 break-inside-avoid print:bg-gray-100 print:border-gray-300">
                          <h3 className="text-xl font-bold text-blue-400 mb-6 flex items-center gap-2 print:text-black">
                            <Icons.Check /> Week {weekReview.week} Self Review
                          </h3>
                          <div className="space-y-4 mb-6">
                            {weekReview.selfQuestions.map((q: string, qIdx: number) => (
                              <div key={qIdx} className="flex gap-3 items-start">
                                 <span className="text-slate-500 font-bold">{qIdx + 1}.</span>
                                 <p className="text-sm text-slate-300 print:text-gray-800">{q}</p>
                              </div>
                            ))}
                          </div>
                          <div className="flex items-center justify-between pt-6 border-t border-blue-500/10 print:border-gray-200">
                             <div className="text-xs text-slate-400 italic">
                               <span className="font-bold text-blue-500 block not-italic uppercase text-[9px] mb-1">Growth Tip</span>
                               {weekReview.improvementTip}
                             </div>
                             <div className="text-center px-4">
                                <span className="text-[9px] font-bold text-slate-600 uppercase block mb-1">Confidence</span>
                                <span className="text-lg font-bold text-blue-500">{weekReview.confidenceScore} / 5</span>
                             </div>
                          </div>
                       </div>
                    )}
                  </React.Fragment>
                );
              })}
           </div>

           {/* Earning Guide Section */}
           <div className="mt-24 p-12 rounded-[3rem] bg-slate-950 border-2 border-green-500/10 break-inside-avoid print:bg-gray-50 print:border-gray-300 print:text-black">
              <div className="flex items-center gap-6 mb-12">
                 <div className="w-20 h-20 rounded-3xl bg-green-500/10 flex items-center justify-center text-3xl text-green-500">💰</div>
                 <div>
                    <h3 className="text-3xl font-bold text-white print:text-black font-heading">Earning Guide</h3>
                    <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.2em]">Ready after {generatedData.firstEarningGuide.readyAfterDays} Days</p>
                 </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 <div className="space-y-8">
                    <div>
                       <span className="text-[10px] font-bold text-green-500 uppercase tracking-widest block mb-3">Action Plan</span>
                       <ul className="space-y-3">
                          {generatedData.firstEarningGuide.actions.map((a: string, i: number) => (
                            <li key={i} className="text-sm text-slate-300 print:text-gray-800 flex gap-3">
                              <span className="text-green-500 font-bold">{i+1}.</span> {a}
                            </li>
                          ))}
                       </ul>
                    </div>
                 </div>
                 <div className="space-y-8">
                    <div className="p-6 bg-slate-900 rounded-3xl border border-slate-800 print:bg-white print:border-gray-200">
                       <span className="text-[10px] font-bold text-pink-500 uppercase tracking-widest block mb-4">Sample Pitch (DM)</span>
                       <p className="text-sm text-slate-200 print:text-black font-mono leading-relaxed whitespace-pre-wrap">"{generatedData.firstEarningGuide.sampleDM}"</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                       <div className="p-5 bg-slate-900 rounded-2xl text-center border border-slate-800">
                          <span className="text-[9px] font-bold text-slate-500 uppercase block mb-1">Pricing</span>
                          <span className="text-sm font-bold text-green-500">{generatedData.firstEarningGuide.beginnerPricing}</span>
                       </div>
                       <div className="p-5 bg-red-500/5 rounded-2xl text-center border border-red-500/10">
                          <span className="text-[9px] font-bold text-red-500 uppercase block mb-1">Mistakes</span>
                          <span className="text-[10px] text-slate-400 font-bold">Check PDF</span>
                       </div>
                    </div>
                 </div>
              </div>
           </div>

           {/* Final Notice & Mandatory Disclaimer */}
           <div className="mt-20 text-center border-t border-slate-900 pt-20 pb-12 print:border-gray-200">
              <p className="text-2xl font-heading font-medium text-slate-200 italic mb-10 max-w-2xl mx-auto leading-relaxed print:text-black">
                "{generatedData.finalNote}"
              </p>

              <div className="bg-slate-950 p-6 rounded-2xl border border-slate-900 mb-12 text-left print:bg-gray-100">
                 <span className="text-red-500 font-bold uppercase text-[9px] tracking-widest block mb-2">⚠️ Important Notice</span>
                 <p className="text-[10px] text-slate-500 leading-relaxed print:text-gray-600">
                    This roadmap is AI-generated based on your answers. Results depend on consistency and effort. No fake earning promises. Skills grow with practice, not shortcuts. Effort hi result layega.
                 </p>
              </div>

              <div className="flex flex-col items-center gap-2">
                 <div className="text-[10px] font-bold text-slate-700 uppercase tracking-[0.8em] print:text-gray-400">SkillShift Engine</div>
                 <div className="text-xs text-blue-500 font-bold">www.skillshift.ai</div>
              </div>
           </div>
        </div>

        <div className="text-center text-slate-500 text-sm py-8 no-print animate-pulse font-medium">
          Tum ready ho. Bas aaj ka Day 1 task karo.
        </div>

        <style>{`
          @media print {
            .no-print { display: none !important; }
            body { background: white !important; color: black !important; padding: 0 !important; margin: 0 !important; }
            #root { max-width: none !important; border: none !important; box-shadow: none !important; margin: 0 !important; width: 100% !important; }
            main { padding: 0 !important; overflow: visible !important; width: 100% !important; }
            .print-area { border: none !important; background: transparent !important; padding: 0 !important; width: 100% !important; margin: 0 !important; border-radius: 0 !important; }
            header, nav { display: none !important; }
            .break-inside-avoid { break-inside: avoid; }
            @page { margin: 1.5cm; size: A4; }
