// Simulating a backend with localStorage for persistence in this environment
const USERS_KEY = 'skillshift_users_db';
const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  signup: async (email: string, password: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800)); // Simulate network latency

    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    if (db.find((u: any) => u.email === email)) {
      throw new Error("Account already exists with this email.");
    }

    const newUser = { email, id: Math.random().toString(36).substr(2, 9) };
    // In a real app, we'd only store the hash. Here we simulate storage.
    db.push({ ...newUser, passwordHash: btoa(password) }); 
    localStorage.setItem(USERS_KEY, JSON.stringify(db));
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));

    return newUser;
  },

  login: async (email: string, password: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800));

    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    const user = db.find((u: any) => u.email === email && u.passwordHash === btoa(password));

    if (!user) {
      throw new Error("Invalid email or password.");
    }

    const sessionUser = { email: user.email, id: user.id };
    localStorage.setItem(SESSION_KEY, JSON.stringify(sessionUser));

    return sessionUser;
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  resetPassword: async (email: string): Promise<void> => {
    await new Promise(r => setTimeout(r, 1000));
    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    const user = db.find((u: any) => u.email === email);
    if (!user) {
      throw new Error("No account found with this email.");
    }
    // Simulation: In reality, backend would send a signed link
    console.log(`Password reset link sent to ${email}`);
  }
};

import React, { useState } from 'react';
import { Icons } from '../constants';
import { authService } from '../services/authService';
import { User } from '../types';

interface AuthProps {
  onSuccess: (user: User) => void;
  onBack: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess, onBack }) => {
  const [mode, setMode] = useState<'login' | 'signup' | 'forgot'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setLoading(true);

    try {
      if (mode === 'signup') {
        const user = await authService.signup(email, password);
        onSuccess(user);
      } else if (mode === 'login') {
        const user = await authService.login(email, password);
        onSuccess(user);
      } else {
        await authService.resetPassword(email);
        setSuccessMsg("Reset link sent! Check your inbox.");
        setTimeout(() => setMode('login'), 3000);
      }
    } catch (err: any) {
      setError(err.message || "An error occurred.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col gap-8 animate-fadeIn py-6">
      <div className="flex flex-col gap-2 text-center">
        <h2 className="text-3xl font-bold font-heading">
          {mode === 'login' ? 'Welcome Back' : mode === 'signup' ? 'Create Account' : 'Reset Password'}
        </h2>
        <p className="text-slate-400 text-sm">
          {mode === 'login' ? 'Log in to save your roadmaps' : mode === 'signup' ? 'No OTP. No drama. Just email.' : 'Enter email for reset link'}
        </p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-4">
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-400 p-4 rounded-xl text-xs font-medium animate-shake">
            {error}
          </div>
        )}
        {successMsg && (
          <div className="bg-green-500/10 border border-green-500/50 text-green-400 p-4 rounded-xl text-xs font-medium">
            {successMsg}
          </div>
        )}

        <div className="flex flex-col gap-1">
          <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">Email Address</label>
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-4 text-sm focus:outline-none focus:border-blue-500 transition-all text-white"
            placeholder="your@email.com"
          />
        </div>

        {mode !== 'forgot' && (
          <div className="flex flex-col gap-1">
            <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">Password</label>
            <input
              type="password"
              required
              minLength={6}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-4 text-sm focus:outline-none focus:border-blue-500 transition-all text-white"
              placeholder="••••••••"
            />
          </div>
        )}

        {mode === 'login' && (
          <button
            type="button"
            onClick={() => setMode('forgot')}
            className="text-right text-[10px] font-bold text-slate-500 uppercase tracking-widest hover:text-blue-400 transition-colors"
          >
            Forgot Password?
          </button>
        )}

        <button
          type="submit"
          disabled={loading}
          className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all mt-4 disabled:opacity-50"
        >
          {loading ? (
             <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
          ) : (
            <>
              <span>{mode === 'login' ? 'Login' : mode === 'signup' ? 'Create Account' : 'Send Link'}</span>
              <Icons.ArrowRight />
            </>
          )}
        </button>
      </form>

      <div className="flex flex-col gap-4 text-center mt-4">
        {mode !== 'forgot' ? (
          <p className="text-sm text-slate-400">
            {mode === 'login' ? "Don't have an account?" : "Already have an account?"}{' '}
            <button
              onClick={() => setMode(mode === 'login' ? 'signup' : 'login')}
              className="text-pink-500 font-bold hover:underline"
            >
              {mode === 'login' ? 'Sign Up' : 'Login'}
            </button>
          </p>
        ) : (
          <button
            onClick={() => setMode('login')}
            className="text-sm text-pink-500 font-bold hover:underline"
          >
            Back to Login
          </button>
        )}

        <button
          onClick={onBack}
          className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.3em] hover:text-slate-400 transition-colors"
        >
          Continue as Guest
        </button>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

