              className={`flex flex-col items-center justify-center gap-1 transition-all duration-300 w-full ${
                currentPage === item.id 
                  ? 'text-pink-500' 
                  : 'text-slate-400 hover:text-slate-200'
              }`}
            >
              <div className={`p-2 rounded-xl transition-colors ${currentPage === item.id ? 'bg-pink-500/10' : ''}`}>
                <item.icon />
              </div>
              <span className="text-[10px] font-medium">{item.label}</span>
            </button>
          ))}
        </div>
      </nav>
    </div>
  );
};

