          >
            <Icons.ArrowRight />
          </button>
        </div>
      </div>
    );
  }

  if (state === EngineState.GENERATING) {
    return (
      <div className="flex flex-col items-center justify-center h-[calc(100vh-220px)] gap-10">
        <ProgressRing size="w-16 h-16" />
