import { User } from "../types";

// Simulating a backend with localStorage for persistence in this environment
const USERS_KEY = 'skillshift_users_db';
const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  signup: async (email: string, password: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800)); // Simulate network latency

    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    if (db.find((u: any) => u.email === email)) {
      throw new Error("Account already exists with this email.");
    }

    const newUser = { email, id: Math.random().toString(36).substr(2, 9) };
    // In a real app, we'd only store the hash. Here we simulate storage.
    db.push({ ...newUser, passwordHash: btoa(password) }); 
    localStorage.setItem(USERS_KEY, JSON.stringify(db));
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));

    return newUser;
  },

  login: async (email: string, password: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800));

    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    const user = db.find((u: any) => u.email === email && u.passwordHash === btoa(password));

    if (!user) {
      throw new Error("Invalid email or password.");
    }

    const sessionUser = { email: user.email, id: user.id };
    localStorage.setItem(SESSION_KEY, JSON.stringify(sessionUser));

    return sessionUser;
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  resetPassword: async (email: string): Promise<void> => {
    await new Promise(r => setTimeout(r, 1000));
    const db = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
    const user = db.find((u: any) => u.email === email);
    if (!user) {
      throw new Error("No account found with this email.");
    }
    // Simulation: In reality, backend would send a signed link
    console.log(`Password reset link sent to ${email}`);
  }
};

