  getOrCreateUserByPhone: async (phone: string): Promise<User> => {
    const users = getTable(TABLES.USERS);
    let user = users.find((u: any) => u.phone === phone);

    if (!user) {
      user = {
        id: Math.random().toString(36).substr(2, 9),
        phone,
        role: ADMIN_PHONES.includes(phone) ? 'admin' : 'user',
        created_at: new Date().toISOString()
      };
      users.push(user);
      saveToTable(TABLES.USERS, users);
    }

    return user;
  },

  findUserByPhone: (phone: string) => {
    const users = getTable(TABLES.USERS);
    return users.find((u: any) => u.phone === phone);
  },

  // OTP Table Operations
  saveOTP: async (phone: string, otp: string): Promise<void> => {
    const otps = getTable(TABLES.OTPS);
    const newOtp = {
      phone,
      otp_hash: btoa(otp), // Simple simulation of hashing
      expires_at: new Date(Date.now() + 5 * 60 * 1000).toISOString(), // 5 mins
      used: false
    };
    otps.push(newOtp);
    saveToTable(TABLES.OTPS, otps);
    console.log(`[SMS Gateway Simulator] Sending OTP ${otp} to ${phone}`);
  },

  verifyOTP: async (phone: string, otp: string): Promise<boolean> => {
    const otps = getTable(TABLES.OTPS);
    const otpRecord = otps.find((o: any) => 
      o.phone === phone && 
      o.otp_hash === btoa(otp) && 
      !o.used && 
      new Date(o.expires_at) > new Date()
    );

    if (otpRecord) {
      otpRecord.used = true;
      saveToTable(TABLES.OTPS, otps);
      return true;
    }
    return false;
  },

  // Roadmaps Table Operations
  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const roadmaps = getTable(TABLES.ROADMAPS);
    const newRecord: RoadmapRecord = {
      id: `rm_${Math.random().toString(36).substr(2, 9)}`,
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };
    roadmaps.push(newRecord);
    saveToTable(TABLES.ROADMAPS, roadmaps);
    return newRecord;
  },

  getRoadmapsByUserId: (user_id: string): RoadmapRecord[] => {
    return getTable(TABLES.ROADMAPS).filter((rm: RoadmapRecord) => rm.user_id === user_id);
  },

  // PDF Files Table Operations
  savePDFMetadata: async (roadmap_id: string, fileName: string, size: number, path: string): Promise<PDFRecord> => {
    const pdfs = getTable(TABLES.PDF_FILES);
    const newRecord: PDFRecord = {
      id: `pdf_${Math.random().toString(36).substr(2, 9)}`,
      roadmap_id,
      file_name: fileName,
      file_path: path,
      file_size: size,
      created_at: new Date().toISOString()
    };
    pdfs.push(newRecord);
    saveToTable(TABLES.PDF_FILES, pdfs);
    return newRecord;
  }
};

import { User } from "../types";
import { dbService } from "./dbService";

const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  sendOTP: async (phone: string): Promise<void> => {
    // Basic rate limiting simulation could go here
    await new Promise(r => setTimeout(r, 800));
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    await dbService.saveOTP(phone, otp);
  },

  verifyOTP: async (phone: string, otp: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800));
    const isValid = await dbService.verifyOTP(phone, otp);

    if (!isValid) {
      throw new Error("Invalid or expired OTP. Please try again.");
    }

    const user = await dbService.getOrCreateUserByPhone(phone);
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  }
};

import React, { useState, useEffect } from 'react';
import { Icons } from '../constants';
import { authService } from '../services/authService';
import { User } from '../types';

interface AuthProps {
  onSuccess: (user: User) => void;
  onBack: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess, onBack }) => {
  const [step, setStep] = useState<'phone' | 'otp'>('phone');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timer, setTimer] = useState(60);

  useEffect(() => {
    let interval: any;
    if (step === 'otp' && timer > 0) {
      interval = setInterval(() => setTimer(prev => prev - 1), 1000);
    }
    return () => clearInterval(interval);
  }, [step, timer]);

  const handleSendOTP = async (e: React.FormEvent) => {
    e.preventDefault();
    if (phone.length !== 10) {
      setError("Please enter a valid 10-digit phone number.");
      return;
    }

    setError('');
    setLoading(true);
    try {
      const fullPhone = `+91${phone}`;
      await authService.sendOTP(fullPhone);
      setStep('otp');
      setTimer(60);
    } catch (err: any) {
      setError(err.message || "Failed to send OTP.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOTP = async (e: React.FormEvent) => {
    e.preventDefault();
    const otpString = otp.join('');
    if (otpString.length !== 6) {
      setError("Please enter the 6-digit OTP.");
      return;
    }

    setError('');
    setLoading(true);
    try {
      const fullPhone = `+91${phone}`;
      const user = await authService.verifyOTP(fullPhone, otpString);
      onSuccess(user);
    } catch (err: any) {
      setError(err.message || "OTP verification failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleOtpChange = (value: string, index: number) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    // Auto focus next
    if (value && index < 5) {
      const nextInput = document.getElementById(`otp-${index + 1}`);
      nextInput?.focus();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent, index: number) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      const prevInput = document.getElementById(`otp-${index - 1}`);
      prevInput?.focus();
    }
  };

  return (
    <div className="flex flex-col gap-8 animate-fadeIn py-6">
      <div className="flex flex-col gap-2 text-center">
        <h2 className="text-3xl font-bold font-heading">
          {step === 'phone' ? 'Phone Login' : 'Verify OTP'}
        </h2>
        <p className="text-slate-400 text-sm">
          {step === 'phone' ? 'India-friendly. Fast. Trusted.' : `Enter the code sent to +91 ${phone}`}
        </p>
      </div>

      <div className="flex flex-col gap-6">
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-400 p-4 rounded-xl text-xs font-medium animate-shake">
            {error}
          </div>
        )}

        {step === 'phone' ? (
          <form onSubmit={handleSendOTP} className="flex flex-col gap-5">
            <div className="flex flex-col gap-1">
              <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">Phone Number</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm">+91</span>
                <input
                  type="tel"
                  required
                  maxLength={10}
                  pattern="[0-9]{10}"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-14 pr-4 py-4 text-sm font-medium focus:outline-none focus:border-blue-500 transition-all text-white tracking-widest"
                  placeholder="9876543210"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading || phone.length !== 10}
              className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-50"
            >
              {loading ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : (
                <>
                  <span>Send OTP</span>
                  <Icons.ArrowRight />
                </>
              )}
            </button>
          </form>
        ) : (
          <form onSubmit={handleVerifyOTP} className="flex flex-col gap-6">
            <div className="flex flex-col gap-4">
              <label className="text-[10px] uppercase font-bold text-slate-500 text-center">6-Digit Code</label>
              <div className="flex justify-between gap-2">
                {otp.map((digit, i) => (
                  <input
                    key={i}
                    id={`otp-${i}`}
                    type="tel"
                    required
                    maxLength={1}
                    value={digit}
                    onChange={(e) => handleOtpChange(e.target.value, i)}
                    onKeyDown={(e) => handleKeyDown(e, i)}
                    className="w-12 h-14 bg-slate-900 border border-slate-800 rounded-xl text-center text-xl font-bold focus:outline-none focus:border-pink-500 transition-all text-white"
                  />
                ))}
              </div>
            </div>

            <button
              type="submit"
              disabled={loading || otp.join('').length !== 6}
              className="w-full py-5 bg-gradient-to-r from-pink-600 to-pink-700 rounded-2xl font-bold shadow-lg neon-glow-pink flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-50"
            >
              {loading ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : (
                <>
                  <span>Verify & Login</span>
                  <Icons.Check />
                </>
              )}
            </button>

            <div className="text-center">
              {timer > 0 ? (
                <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">Resend OTP in <span className="text-pink-500 font-bold">{timer}s</span></p>
              ) : (
                <button
                  type="button"
                  onClick={handleSendOTP}
                  className="text-xs text-blue-500 font-bold uppercase tracking-widest hover:underline"
                >
                  Resend OTP Now
                </button>
              )}
            </div>

            <button
              type="button"
              onClick={() => setStep('phone')}
              className="text-[10px] font-bold text-slate-600 uppercase tracking-widest hover:text-slate-400 transition-colors"
            >
              Change Phone Number
            </button>
          </form>
        )}

        <button
          onClick={onBack}
          className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.3em] text-center hover:text-slate-400 transition-colors"
        >
          Continue as Guest
        </button>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

export default Auth;

