import { RoadmapRecord, PDFRecord, User, UserRole } from "../types";

const TABLES = {
  USERS: 'skillshift_users',
  ROADMAPS: 'skillshift_roadmaps',
  PDF_FILES: 'skillshift_pdf_files',
  OTPS: 'skillshift_otps'
};

// Admin Whitelist
const ADMIN_PHONES = ["+919991234567", "+918881234567"];

// Simulated DB Utility
const getTable = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const saveToTable = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

export const dbService = {
  // Users Table Operations
  getOrCreateUserByPhone: async (phone: string): Promise<User> => {
    const users = getTable(TABLES.USERS);
    let user = users.find((u: any) => u.phone === phone);

    if (!user) {
      user = {
        id: Math.random().toString(36).substr(2, 9),
        phone,
        role: ADMIN_PHONES.includes(phone) ? 'admin' : 'user',
        created_at: new Date().toISOString()
      };
      users.push(user);
      saveToTable(TABLES.USERS, users);
    }

    return user;
  },

  findUserByPhone: (phone: string) => {
    const users = getTable(TABLES.USERS);
    return users.find((u: any) => u.phone === phone);
  },

  // OTP Table Operations (Enhanced for Resend Logic)
  getOTPStats: (phone: string) => {
    const otps = getTable(TABLES.OTPS);
    const now = Date.now();
    const fifteenMinsAgo = now - (15 * 60 * 1000);

    const recentOTPs = otps.filter((o: any) => 
      o.phone === phone && 
      new Date(o.created_at).getTime() > fifteenMinsAgo
    );

    const lastOTP = recentOTPs.length > 0 ? recentOTPs[recentOTPs.length - 1] : null;

    return {
      countLast15Mins: recentOTPs.length,
      lastSentAt: lastOTP ? new Date(lastOTP.created_at).getTime() : 0
    };
  },

  invalidateOldOTPs: (phone: string) => {
    const otps = getTable(TABLES.OTPS);
    const updated = otps.map((o: any) => 
      o.phone === phone ? { ...o, used: true } : o
    );
    saveToTable(TABLES.OTPS, updated);
  },

  saveOTP: async (phone: string, otp: string): Promise<void> => {
    // 1. Invalidate previous ones for this number
    dbService.invalidateOldOTPs(phone);

    // 2. Save new one
    const otps = getTable(TABLES.OTPS);
    const newOtp = {
      phone,
      otp_hash: btoa(otp),
      expires_at: new Date(Date.now() + 5 * 60 * 1000).toISOString(), // 5 mins
      created_at: new Date().toISOString(),
      used: false
    };
    otps.push(newOtp);
    saveToTable(TABLES.OTPS, otps);

    // Log for local debugging since real SMS costs money
    console.debug(`[SMS GATEWAY] OTP ${otp} -> ${phone}`);
  },

  verifyOTP: async (phone: string, otp: string): Promise<boolean> => {
    const otps = getTable(TABLES.OTPS);
    const otpRecord = otps.find((o: any) => 
      o.phone === phone && 
      o.otp_hash === btoa(otp) && 
      !o.used && 
      new Date(o.expires_at) > new Date()
    );

    if (otpRecord) {
      otpRecord.used = true;
      saveToTable(TABLES.OTPS, otps);
      return true;
    }
    return false;
  },

  // Roadmaps Table Operations
  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const roadmaps = getTable(TABLES.ROADMAPS);
    const newRecord: RoadmapRecord = {
      id: `rm_${Math.random().toString(36).substr(2, 9)}`,
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };
    roadmaps.push(newRecord);
    saveToTable(TABLES.ROADMAPS, roadmaps);
    return newRecord;
  },

  getRoadmapsByUserId: (user_id: string): RoadmapRecord[] => {
    return getTable(TABLES.ROADMAPS).filter((rm: RoadmapRecord) => rm.user_id === user_id);
  },

  // PDF Files Table Operations
  savePDFMetadata: async (roadmap_id: string, fileName: string, size: number, path: string): Promise<PDFRecord> => {
    const pdfs = getTable(TABLES.PDF_FILES);
    const newRecord: PDFRecord = {
      id: `pdf_${Math.random().toString(36).substr(2, 9)}`,
      roadmap_id,
      file_name: fileName,
      file_path: path,
      file_size: size,
      created_at: new Date().toISOString()
    };
    pdfs.push(newRecord);
    saveToTable(TABLES.PDF_FILES, pdfs);
    return newRecord;
  }
};

