export const authService = {
  sendOTP: async (phone: string, setStatus?: (s: string) => void): Promise<void> => {
    const stats = dbService.getOTPStats(phone);
    const now = Date.now();

    // 1. Cooldown Check (60 seconds)
    if (stats.lastSentAt > 0 && (now - stats.lastSentAt) < 60000) {
      const wait = Math.ceil((60000 - (now - stats.lastSentAt)) / 1000);
      throw new Error(`Thoda sabar! ${wait} seconds baad try karo.`);
    }

    // 2. Max Attempts Check (3 per 15 mins)
    if (stats.countLast15Mins >= 3) {
      throw new Error("Maximum attempts reached. 15 minutes baad try karo.");
    }

    // 3. BRAIN: Generate OTP using AI Studio Logic
    setStatus?.("AI thinking...");
    const brainResponse = await processOTPLogic('GENERATE', {});
    const otp = brainResponse?.otp || Math.floor(100000 + Math.random() * 900000).toString();

    // 4. HAND: Call SMS Gateway API (Fast2SMS logic)
    setStatus?.("Sending SMS...");
    try {
      // Simulation of Hand Delivery
      /*
      await fetch("https://www.fast2sms.com/dev/bulkV2", {
        method: "POST",
        headers: {
          "authorization": FAST2SMS_API_KEY,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          "route": "otp",
          "variables_values": otp,
          "numbers": phone.replace('+91', '')
        })
      });
      */

      // Save to local DB simulation
      await dbService.saveOTP(phone, otp);
    } catch (err) {
      console.error("SMS Gateway Error:", err);
      throw new Error("SMS send nahi ho paya. Server busy lag raha hai.");
    }
  },

  verifyOTP: async (phone: string, otp: string): Promise<User> => {
    await new Promise(r => setTimeout(r, 800));

    // 5. BRAIN: Verify logic check
    // In this simulation, we check local storage which holds the 'brain's' previous output
    const isValid = await dbService.verifyOTP(phone, otp);

    if (!isValid) {
      throw new Error("OTP galat hai ya expire ho gaya.");
    }

    const user = await dbService.getOrCreateUserByPhone(phone);
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  }
};

