import React, { useState } from 'react';
import { Icons } from '../constants';
import { authService } from '../services/authService';
import { User, Gender } from '../types';

interface ProfileEntryProps {
  onSuccess: (user: User) => void;
  onBack: () => void;
}

const ProfileEntry: React.FC<ProfileEntryProps> = ({ onSuccess, onBack }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [gender, setGender] = useState<Gender>('Male');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError("Naam batana zaroori hai boss.");
      return;
    }
    if (phone.length !== 10) {
      setError("Ek valid 10-digit mobile number dalo.");
      return;
    }

    setError('');
    setLoading(true);
    try {
      const user = await authService.saveProfile(name, phone, gender);
      onSuccess(user);
    } catch (err: any) {
      setError("Kuch issue ho gaya. Wapas try karo.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col gap-8 animate-fadeIn py-6">
      <div className="flex flex-col gap-2 text-center">
        <h2 className="text-3xl font-bold font-heading">Apni Profile Setup Karo</h2>
        <p className="text-slate-400 text-sm">
          No OTP, No Password. Bas basic details.
        </p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-6">
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-400 p-4 rounded-xl text-xs font-medium animate-shake text-center">
            {error}
          </div>
        )}

        {/* Name Input */}
        <div className="flex flex-col gap-1">
          <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">Poora Naam</label>
          <input
            type="text"
            required
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-4 text-sm font-medium focus:outline-none focus:border-blue-500 transition-all text-white"
            placeholder="e.g. Satyam Kumar"
          />
        </div>

        {/* Phone Input */}
        <div className="flex flex-col gap-1">
          <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">WhatsApp Number</label>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm tracking-tight">+91</span>
            <input
              type="tel"
              required
              maxLength={10}
              value={phone}
              onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
              className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-14 pr-4 py-4 text-sm font-medium focus:outline-none focus:border-blue-500 transition-all text-white tracking-widest"
              placeholder="9876543210"
            />
          </div>
          <p className="text-[9px] text-slate-600 mt-1 ml-1">No OTP will be sent. Just for reference.</p>
        </div>

        {/* Gender Selection */}
        <div className="flex flex-col gap-1">
          <label className="text-[10px] uppercase font-bold text-slate-500 ml-1">Gender</label>
          <div className="flex gap-3 mt-1">
            {(['Male', 'Female'] as Gender[]).map((g) => (
              <button
                key={g}
                type="button"
                onClick={() => setGender(g)}
                className={`flex-1 py-3.5 rounded-xl border text-sm font-bold transition-all ${
                  gender === g 
                    ? 'bg-blue-600/20 border-blue-500 text-blue-400' 
                    : 'bg-slate-900 border-slate-800 text-slate-500'
                }`}
              >
                {g}
              </button>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all mt-4"
        >
          {loading ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : (
            <>
              <span>Continue</span>
              <Icons.ArrowRight />
            </>
          )}
        </button>
      </form>

      <button
        onClick={onBack}
        className="text-[10px] font-bold text-slate-700 uppercase tracking-[0.4em] text-center hover:text-slate-500 transition-colors"
      >
        Wapas Jao
      </button>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

export default ProfileEntry;

