export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle
        className="opacity-10"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      />
      <circle
        className="text-blue-500"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeDasharray="80"
        strokeDashoffset="60"
        strokeLinecap="round"
      />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }

    const timer = setTimeout(() => setIsLoaded(true), 1200);
    return () => clearTimeout(timer);
  }, []);

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={setCurrentPage} user={user} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return <Roadmaps user={user} onAuthRequired={() => setCurrentPage(Page.PROFILE_ENTRY)} />;
      case Page.BOOST:
        return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            onSuccess={(u) => {
              setUser(u);
              setCurrentPage(Page.HOME);
            }} 
            onBack={() => setCurrentPage(Page.HOME)} 
          />
        );
      default:
        return <Home onNavigate={setCurrentPage} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-2xl font-semibold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <p className="text-slate-500 text-[10px] tracking-[0.2em] uppercase font-medium animate-pulse">Initializing</p>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentPage={currentPage} 
      onPageChange={setCurrentPage} 
      user={user} 
      onLogout={handleLogout}
    >
      {renderPage()}
    </Layout>
  );
};

export default App;

