import { User, Gender } from "../types";
import { dbService } from "./dbService";
import { processOTPLogic } from "./geminiService";

const SESSION_KEY = 'skillshift_current_user';
const OTP_STORE_KEY = 'skillshift_otp_store';

export const authService = {
  // Simplified entry instead of auth
  saveProfile: async (name: string, phone: string, gender: Gender): Promise<User> => {
    // Artificial delay for feedback
    await new Promise(r => setTimeout(r, 600));

    const user = await dbService.createProfile(name, phone, gender);
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  // Added sendOTP to fix Property 'sendOTP' does not exist error on authService
  sendOTP: async (phone: string, onStatus: (status: string) => void): Promise<void> => {
    onStatus('AI Brain generating secure code...');
    const result = await processOTPLogic('GENERATE', {});
    if (result && result.otp) {
      // Store it locally for the verification simulation
      localStorage.setItem(OTP_STORE_KEY, JSON.stringify({ phone, otp: result.otp }));
      onStatus(`OTP (Simulated): ${result.otp}`);
      return;
    }
    throw new Error("Failed to generate OTP. Please try again.");
  },

  // Added verifyOTP to fix Property 'verifyOTP' does not exist error on authService
  verifyOTP: async (phone: string, otpString: string): Promise<User> => {
    const storedData = localStorage.getItem(OTP_STORE_KEY);
    if (!storedData) throw new Error("No active OTP request. Please try again.");

    const { phone: storedPhone, otp: storedOtp } = JSON.parse(storedData);

    if (storedPhone !== phone) {
      throw new Error("Phone number mismatch.");
    }

    const result = await processOTPLogic('VERIFY', { inputOTP: otpString, storedCode: storedOtp });

    if (result && result.verified) {
      // Create profile with default values if it doesn't exist
      const cleanPhone = phone.replace('+91', '');
      const user = await dbService.createProfile("SkillShifter", cleanPhone, 'Other');
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      localStorage.removeItem(OTP_STORE_KEY);
      return user;
    }
    throw new Error("Invalid OTP code.");
  },

  logout: () => {
    localStorage.removeItem(SESSION_KEY);
    localStorage.removeItem(OTP_STORE_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  }
};

