import { RoadmapRecord, PDFRecord, User, Gender } from "../types";

const TABLES = {
  USERS: 'skillshift_users',
  ROADMAPS: 'skillshift_roadmaps',
  PDF_FILES: 'skillshift_pdf_files'
};

// Admin Whitelist (Optional reference)
// NOTE: Change these numbers to your own phone numbers to test admin access
const ADMIN_PHONES = ["9991234567", "8881234567", "9876543210"];

// Simulated DB Utility
const getTable = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const saveToTable = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

export const dbService = {
  // Simple Profile Creation
  createProfile: async (name: string, phone: string, gender: Gender): Promise<User> => {
    const users = getTable(TABLES.USERS);

    // Check if user already exists with this phone
    let existingUser = users.find((u: any) => u.phone === phone);

    if (existingUser) {
      // Update existing user with new name/gender if needed
      existingUser.name = name;
      existingUser.gender = gender;
      saveToTable(TABLES.USERS, users);
      return existingUser;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      phone,
      gender,
      role: ADMIN_PHONES.includes(phone) ? 'admin' : 'user',
      created_at: new Date().toISOString()
    };

    users.push(newUser);
    saveToTable(TABLES.USERS, users);
    return newUser;
  },

  getAllUsers: (): User[] => {
    return getTable(TABLES.USERS);
  },

  getAllRoadmaps: (): RoadmapRecord[] => {
    return getTable(TABLES.ROADMAPS);
  },

  // Roadmaps Table Operations
  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const roadmaps = getTable(TABLES.ROADMAPS);
    const newRecord: RoadmapRecord = {
      id: `rm_${Math.random().toString(36).substr(2, 9)}`,
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };
    roadmaps.push(newRecord);
    saveToTable(TABLES.ROADMAPS, roadmaps);
    return newRecord;
  },

  getRoadmapsByUserId: (user_id: string): RoadmapRecord[] => {
    return getTable(TABLES.ROADMAPS).filter((rm: RoadmapRecord) => rm.user_id === user_id);
  },

  // PDF Files Table Operations
  savePDFMetadata: async (roadmap_id: string, fileName: string, size: number, path: string): Promise<PDFRecord> => {
    const pdfs = getTable(TABLES.PDF_FILES);
    const newRecord: PDFRecord = {
      id: `pdf_${Math.random().toString(36).substr(2, 9)}`,
      roadmap_id,
      file_name: fileName,
      file_path: path,
      file_size: size,
      created_at: new Date().toISOString()
    };
    pdfs.push(newRecord);
    saveToTable(TABLES.PDF_FILES, pdfs);
    return newRecord;
  }
};

import React, { useState, useMemo } from 'react';
import { dbService } from '../services/dbService';
import { User, RoadmapRecord } from '../types';

const AdminDashboard: React.FC = () => {
  const [filterType, setFilterType] = useState<'all' | 'today' | 'week'>('all');
  const [searchSkill, setSearchSkill] = useState('');

  const users = useMemo(() => dbService.getAllUsers(), []);
  const roadmaps = useMemo(() => dbService.getAllRoadmaps(), []);

  const stats = useMemo(() => {
    const now = new Date();
    const today = new Date(now.setHours(0, 0, 0, 0));

    return {
      totalUsers: users.length,
      todayUsers: users.filter(u => new Date(u.created_at) >= today).length,
      totalRoadmaps: roadmaps.length
    };
  }, [users, roadmaps]);

  const skillUsage = useMemo(() => {
    const summary: Record<string, number> = {};
    roadmaps.forEach(rm => {
      summary[rm.skill_name] = (summary[rm.skill_name] || 0) + 1;
    });
    return Object.entries(summary).sort((a, b) => b[1] - a[1]);
  }, [roadmaps]);

  const filteredData = useMemo(() => {
    let result = roadmaps.map(rm => {
      const user = users.find(u => u.id === rm.user_id);
      return {
        userName: user?.name || 'Unknown',
        contact: user?.phone || 'N/A',
        gender: user?.gender || 'N/A',
        skill: rm.skill_name,
        date: new Date(rm.created_at)
      };
    });

    if (filterType === 'today') {
      const today = new Date(new Date().setHours(0, 0, 0, 0));
      result = result.filter(r => r.date >= today);
    } else if (filterType === 'week') {
      const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
      result = result.filter(r => r.date >= weekAgo);
    }

    if (searchSkill.trim()) {
      result = result.filter(r => r.skill.toLowerCase().includes(searchSkill.toLowerCase()));
    }

    return result.sort((a, b) => b.date.getTime() - a.date.getTime());
  }, [roadmaps, users, filterType, searchSkill]);

  return (
    <div className="flex flex-col gap-8 animate-fadeIn py-6">
      <div className="flex flex-col gap-2">
        <h2 className="text-3xl font-bold font-heading">Admin Dashboard</h2>
        <p className="text-slate-400 text-sm">Real-time overview of SkillShift activity.</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="glass-card p-6 rounded-3xl border-blue-500/20">
          <div className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1">Total Users</div>
          <div className="text-3xl font-bold">{stats.totalUsers}</div>
        </div>
        <div className="glass-card p-6 rounded-3xl border-pink-500/20">
          <div className="text-[10px] font-bold text-pink-400 uppercase tracking-widest mb-1">Today's Entry</div>
          <div className="text-3xl font-bold">{stats.todayUsers}</div>
        </div>
        <div className="glass-card p-6 rounded-3xl border-green-500/20">
          <div className="text-[10px] font-bold text-green-400 uppercase tracking-widest mb-1">Roadmaps Gen</div>
          <div className="text-3xl font-bold">{stats.totalRoadmaps}</div>
        </div>
      </div>

      {/* Usage Summary */}
      <div className="flex flex-col gap-4">
        <h3 className="text-lg font-bold font-heading">Roadmap Usage Summary</h3>
        <div className="flex flex-wrap gap-3">
          {skillUsage.map(([skill, count]) => (
            <div key={skill} className="bg-slate-900 border border-slate-800 px-4 py-2 rounded-2xl flex items-center gap-3">
              <span className="text-xs font-medium text-slate-300">{skill}</span>
              <span className="bg-blue-600/20 text-blue-400 text-[10px] font-bold px-2 py-0.5 rounded-full">{count}</span>
            </div>
          ))}
          {skillUsage.length === 0 && <p className="text-slate-500 text-xs">No data yet.</p>}
        </div>
      </div>

      {/* Activity Table */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row gap-4 items-center justify-between">
          <h3 className="text-lg font-bold font-heading">Recent Activity</h3>
          <div className="flex gap-2 w-full sm:w-auto">
            <select 
              value={filterType} 
              onChange={(e) => setFilterType(e.target.value as any)}
              className="bg-slate-900 border border-slate-800 rounded-xl px-3 py-2 text-xs font-bold text-slate-300 focus:outline-none"
            >
              <option value="all">All Time</option>
              <option value="today">Today</option>
              <option value="week">Last 7 Days</option>
            </select>
            <input 
              type="text" 
              placeholder="Filter by Skill..." 
              value={searchSkill}
              onChange={(e) => setSearchSkill(e.target.value)}
              className="flex-1 sm:w-48 bg-slate-900 border border-slate-800 rounded-xl px-3 py-2 text-xs text-white placeholder:text-slate-600 focus:outline-none focus:border-blue-500"
            />
          </div>
        </div>

        <div className="glass-card rounded-3xl overflow-hidden border-slate-800">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-900/50 border-b border-slate-800">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-500 uppercase tracking-widest text-[10px]">User Name</th>
                  <th className="px-6 py-4 font-bold text-slate-500 uppercase tracking-widest text-[10px]">Contact</th>
                  <th className="px-6 py-4 font-bold text-slate-500 uppercase tracking-widest text-[10px]">Gender</th>
                  <th className="px-6 py-4 font-bold text-slate-500 uppercase tracking-widest text-[10px]">Roadmap</th>
                  <th className="px-6 py-4 font-bold text-slate-500 uppercase tracking-widest text-[10px]">Date & Time</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-800">
                {filteredData.map((row, i) => (
                  <tr key={i} className="hover:bg-slate-800/20 transition-colors">
                    <td className="px-6 py-4 font-semibold text-slate-200">{row.userName}</td>
                    <td className="px-6 py-4 text-slate-400 font-mono text-xs">{row.contact}</td>
                    <td className="px-6 py-4">
                      <span className={`px-2 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest ${
                        row.gender === 'Male' ? 'bg-blue-500/10 text-blue-400' : 'bg-pink-500/10 text-pink-400'
                      }`}>
                        {row.gender}
                      </span>
                    </td>
                    <td className="px-6 py-4 font-medium text-blue-400">{row.skill}</td>
                    <td className="px-6 py-4 text-slate-500 text-[10px]">
                      {row.date.toLocaleDateString()} {row.date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </td>
                  </tr>
                ))}
                {filteredData.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-600 italic">No activity found matching filters.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

