import React, { useState, useMemo } from 'react';
import { dbService } from '../services/dbService';
import { User, RoadmapRecord } from '../types';

interface AdminDashboardProps {
  user: User | null;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ user }) => {
  const [filterType, setFilterType] = useState<'all' | 'today' | 'week'>('all');
  const [searchSkill, setSearchSkill] = useState('');

  // Access Restriction Check
  if (!user || user.role !== 'admin') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center animate-fadeIn">
        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="11" x="3" y="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
        </div>
        <h2 className="text-2xl font-bold font-heading text-white mb-2">Access Restricted</h2>
        <p className="text-slate-500 text-sm max-w-xs">You do not have permission to view this panel.</p>
      </div>
    );
  }

  const users = useMemo(() => dbService.getAllUsers(), []);
  const roadmaps = useMemo(() => dbService.getAllRoadmaps(), []);

  const stats = useMemo(() => {
    const now = new Date();
    const today = new Date(now.setHours(0, 0, 0, 0));

    return {
      totalUsers: users.length,
      todayUsers: users.filter(u => new Date(u.created_at) >= today).length,
      totalRoadmaps: roadmaps.length
    };
  }, [users, roadmaps]);

  const skillUsage = useMemo(() => {
    const summary: Record<string, number> = {};
    roadmaps.forEach(rm => {
      summary[rm.skill_name] = (summary[rm.skill_name] || 0) + 1;
    });
    return Object.entries(summary).sort((a, b) => b[1] - a[1]);
  }, [roadmaps]);

  const filteredData = useMemo(() => {
    let result = roadmaps.map(rm => {
      const u = users.find(usr => usr.id === rm.user_id);
      return {
        userName: u?.name || 'Unknown',
        contact: u?.phone || 'N/A',
        gender: u?.gender || 'N/A',
        skill: rm.skill_name,
        date: new Date(rm.created_at)
      };
    });

    if (filterType === 'today') {
      const today = new Date(new Date().setHours(0, 0, 0, 0));
      result = result.filter(r => r.date >= today);
    } else if (filterType === 'week') {
      const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
      result = result.filter(r => r.date >= weekAgo);
    }

    if (searchSkill.trim()) {
      result = result.filter(r => r.skill.toLowerCase().includes(searchSkill.toLowerCase()));
    }

    return result.sort((a, b) => b.date.getTime() - a.date.getTime());
  }, [roadmaps, users, filterType, searchSkill]);

  return (
    <div className="flex flex-col gap-8 animate-fadeIn py-6">
      <div className="flex flex-col gap-2">
        <h2 className="text-3xl font-bold font-heading">Admin Dashboard</h2>
        <p className="text-slate-400 text-sm italic">Confidential activity log.</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 gap-4">
        <div className="glass-card p-6 rounded-3xl flex justify-between items-center border-slate-800">
          <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">Total Users Entered</div>
          <div className="text-3xl font-bold text-blue-400">{stats.totalUsers}</div>
        </div>
        <div className="glass-card p-6 rounded-3xl flex justify-between items-center border-slate-800">
          <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">Today's Users</div>
          <div className="text-3xl font-bold text-pink-400">{stats.todayUsers}</div>
        </div>
        <div className="glass-card p-6 rounded-3xl flex justify-between items-center border-slate-800">
          <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">Total Roadmaps Generated</div>
          <div className="text-3xl font-bold text-green-400">{stats.totalRoadmaps}</div>
        </div>
      </div>

      {/* Usage Summary */}
      <div className="flex flex-col gap-4">
        <h3 className="text-lg font-bold font-heading">Most Used Roadmaps</h3>
        <div className="flex flex-col gap-2">
          {skillUsage.map(([skill, count]) => (
            <div key={skill} className="bg-slate-900 border border-slate-800 p-4 rounded-2xl flex justify-between items-center">
              <span className="text-sm font-medium text-slate-300">{skill}</span>
              <span className="text-blue-400 font-bold">{count}</span>
            </div>
          ))}
          {skillUsage.length === 0 && <p className="text-slate-600 text-xs italic">No roadmaps generated yet.</p>}
        </div>
      </div>

      {/* Activity Table */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col gap-4">
          <h3 className="text-lg font-bold font-heading">User Details</h3>
          <div className="flex gap-2">
            <select 
              value={filterType} 
              onChange={(e) => setFilterType(e.target.value as any)}
              className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-xs font-bold text-slate-300 focus:outline-none"
            >
              <option value="all">All Time</option>
              <option value="today">Today</option>
              <option value="week">Last 7 Days</option>
            </select>
          </div>
        </div>

        <div className="flex flex-col gap-4">
          {filteredData.map((row, i) => (
            <div key={i} className="glass-card p-5 rounded-2xl border-slate-800 flex flex-col gap-2">
              <div className="flex justify-between items-start">
                <div className="font-bold text-slate-100">{row.userName}</div>
                <div className="text-[10px] text-slate-500 font-mono">{row.date.toLocaleDateString()}</div>
              </div>
              <div className="text-xs text-blue-400 font-medium">{row.skill}</div>
              <div className="flex justify-between items-center mt-2 border-t border-slate-800/50 pt-2">
                <span className="text-[11px] text-slate-500 font-mono">{row.contact}</span>
                <span className={`text-[9px] font-bold uppercase tracking-widest ${
                  row.gender === 'Male' ? 'text-blue-500' : 'text-pink-500'
                }`}>
                  {row.gender}
                </span>
              </div>
            </div>
          ))}
          {filteredData.length === 0 && (
            <div className="text-center py-12 text-slate-600 italic text-sm">No activity recorded.</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

export enum Page {
  HOME = 'home',
  MENTOR = 'mentor',
  FINDER = 'finder',
  ROADMAPS = 'roadmaps',
  BOOST = 'boost',
  PROFILE_ENTRY = 'profile_entry',
  PREPARING = 'preparing',
  ADMIN_DASHBOARD = 'admin_dashboard',
  ADMIN_REPORT = 'admin_report'
}

export type UserRole = 'admin' | 'user';
export type Gender = 'Male' | 'Female' | 'Other';

export interface User {
  id: string;
  name: string;
  phone: string;
  gender: Gender;
  role: UserRole;
  created_at: string;
}

export interface RoadmapRecord {
  id: string;
  user_id: string;
  skill_name: string;
  user_goal: string;
  overview: string;
  ai_json: any;
  created_at: string;
}

export interface PDFRecord {
  id: string;
  roadmap_id: string;
  file_name: string;
  file_path: string; 
  file_size: number;
  created_at: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface RoadmapStage {
  days: string;
  title: string;
  task: string;
}

export interface Skill {
  id: string;
  title: string;
  goal: string;
  description: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  timeToStart: string;
  phoneRequired: boolean;
  tools: string[];
  roadmapStages: RoadmapStage[];
}

import React, { useMemo } from 'react';
import { dbService } from '../services/dbService';
import { User } from '../types';

interface AdminReportProps {
  user: User | null;
}

const AdminReport: React.FC<AdminReportProps> = ({ user }) => {
  // Access Restriction Check
  if (!user || user.role !== 'admin') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center animate-fadeIn">
        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="11" x="3" y="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
        </div>
        <h2 className="text-2xl font-bold font-heading text-white mb-2">Access Restricted</h2>
        <p className="text-slate-500 text-sm max-w-xs">You do not have permission to view this report.</p>
      </div>
    );
  }

  const reportData = useMemo(() => {
    const allUsers = dbService.getAllUsers();
    const allRoadmaps = dbService.getAllRoadmaps();

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const todayUsers = allUsers.filter(u => new Date(u.created_at) >= today);
    const todayRoadmaps = allRoadmaps.filter(r => new Date(r.created_at) >= today);

    // Roadmap breakdown
    const roadmapCounts: Record<string, number> = {};
    todayRoadmaps.forEach(rm => {
      roadmapCounts[rm.skill_name] = (roadmapCounts[rm.skill_name] || 0) + 1;
    });

    const sortedRoadmaps = Object.entries(roadmapCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3);

    // Gender breakdown
    const maleCount = todayUsers.filter(u => u.gender === 'Male').length;
    const femaleCount = todayUsers.filter(u => u.gender === 'Female').length;

    const topRoadmap = sortedRoadmaps[0]?.[0] || "general skills";

    return {
      date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' }),
      totalUsers: todayUsers.length,
      totalRoadmaps: todayRoadmaps.length,
      topRoadmaps: sortedRoadmaps,
      male: maleCount,
      female: femaleCount,
      insight: `User interest is shifting towards ${topRoadmap}.`
    };
  }, []);

  return (
    <div className="flex flex-col gap-6 animate-fadeIn py-8 px-2 font-mono text-sm leading-relaxed text-slate-300">
      <div className="border-b border-slate-800 pb-4 mb-4">
        <h2 className="text-xl font-bold text-white mb-1">Daily Activity Report</h2>
        <p className="text-slate-500">{reportData.date}</p>
      </div>

      <div className="space-y-6">
        <section>
          <div className="text-white font-bold mb-2">--------------------------------</div>
          <div className="text-white font-bold mb-2">Daily Report – {reportData.date}</div>

          <ul className="list-none space-y-1">
            <li>• Total users today: {reportData.totalUsers}</li>
            <li>• Total roadmaps generated today: {reportData.totalRoadmaps}</li>
          </ul>
        </section>

        <section>
          <div className="text-white font-bold mb-2">Most selected roadmaps today:</div>
          <ol className="list-none space-y-1">
            {reportData.topRoadmaps.length > 0 ? reportData.topRoadmaps.map(([name, count], i) => (
              <li key={i}>{i + 1}) {name} – {count} users</li>
            )) : (
              <li>No roadmaps generated today yet.</li>
            )}
          </ol>
        </section>

        <section>
          <div className="text-white font-bold mb-2">User breakdown:</div>
          <ul className="list-none space-y-1">
            <li>• Male: {reportData.male}</li>
            <li>• Female: {reportData.female}</li>
          </ul>
          <div className="text-white font-bold mt-2">--------------------------------</div>
        </section>

        <section className="pt-4 italic text-slate-400">
          “{reportData.insight}”
        </section>
      </div>

      <div className="mt-12 text-center">
        <button 
          onClick={() => window.print()}
          className="text-[10px] uppercase tracking-widest font-bold text-slate-600 hover:text-slate-400"
        >
          Print Report
        </button>
      </div>
    </div>
  );
};

export default AdminReport;

import React, { useState, useEffect } from 'react';
import { Page, User } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';
import ProfileEntry from './pages/ProfileEntry';
import PreparingRoadmap from './pages/PreparingRoadmap';
import AdminDashboard from './pages/AdminDashboard';
import AdminReport from './pages/AdminReport';
import { authService } from './services/authService';

export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle
        className="opacity-10"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      />
      <circle
        className="text-blue-500"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeDasharray="80"
        strokeDashoffset="60"
        strokeLinecap="round"
      />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }

    // Secret URL detection
    const path = window.location.pathname;
    if (path === '/admin-overview' || path === '/hidden-admin-panel') {
      setCurrentPage(Page.ADMIN_DASHBOARD);
    } else if (path === '/admin-daily-report') {
      setCurrentPage(Page.ADMIN_REPORT);
    }

    const timer = setTimeout(() => setIsLoaded(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
    // Reset path if in admin
    if (window.location.pathname.includes('admin')) {
      window.history.pushState({}, '', '/');
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={setCurrentPage} user={user} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return <Roadmaps user={user} onAuthRequired={() => setCurrentPage(Page.PROFILE_ENTRY)} />;
      case Page.BOOST:
        return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            onSuccess={(u) => {
              setUser(u);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => setCurrentPage(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap 
            user={user} 
            onComplete={() => setCurrentPage(Page.ROADMAPS)} 
          />
        ) : <Home onNavigate={setCurrentPage} user={null} />;
      case Page.ADMIN_DASHBOARD:
        return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT:
        return <AdminReport user={user} />;
      default:
        return <Home onNavigate={setCurrentPage} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-3xl font-bold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <div className="flex gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-100"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentPage={currentPage} 
      onPageChange={setCurrentPage} 
      user={user} 
      onLogout={handleLogout}
    >
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Page, User } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';
import ProfileEntry from './pages/ProfileEntry';
import PreparingRoadmap from './pages/PreparingRoadmap';
import AdminDashboard from './pages/AdminDashboard';
import AdminReport from './pages/AdminReport';
import { authService } from './services/authService';

export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle
        className="opacity-10"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      />
      <circle
        className="text-blue-500"
        cx="25"
        cy="25"
        r="20"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeDasharray="80"
        strokeDashoffset="60"
        strokeLinecap="round"
      />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [authRedirectMessage, setAuthRedirectMessage] = useState<string | null>(null);

  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }

    // Secret URL detection
    const path = window.location.pathname;
    if (path === '/admin-overview' || path === '/hidden-admin-panel') {
      setCurrentPage(Page.ADMIN_DASHBOARD);
    } else if (path === '/admin-daily-report') {
      setCurrentPage(Page.ADMIN_REPORT);
    }

    const timer = setTimeout(() => setIsLoaded(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const handlePageChange = (page: Page, message?: string) => {
    // Access control for roadmaps
    if (page === Page.ROADMAPS && !user) {
      setAuthRedirectMessage(message || "Roadmap dekhne ke liye pehle apni basic details bharo.");
      setCurrentPage(Page.PROFILE_ENTRY);
      return;
    }

    // Reset message if going elsewhere
    if (page !== Page.PROFILE_ENTRY) {
      setAuthRedirectMessage(null);
    }

    setCurrentPage(page);
  };

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
    // Reset path if in admin
    if (window.location.pathname.includes('admin')) {
      window.history.pushState({}, '', '/');
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={handlePageChange} user={user} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return (
          <Roadmaps 
            user={user} 
            onAuthRequired={(msg) => handlePageChange(Page.PROFILE_ENTRY, msg)} 
          />
        );
      case Page.BOOST:
        return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            redirectMessage={authRedirectMessage}
            onSuccess={(u) => {
              setUser(u);
              setAuthRedirectMessage(null);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => handlePageChange(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap 
            user={user} 
            onComplete={() => setCurrentPage(Page.ROADMAPS)} 
          />
        ) : <Home onNavigate={handlePageChange} user={null} />;
      case Page.ADMIN_DASHBOARD:
        return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT:
        return <AdminReport user={user} />;
      default:
        return <Home onNavigate={handlePageChange} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-3xl font-bold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <div className="flex gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-100"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentPage={currentPage} 
      onPageChange={handlePageChange} 
      user={user} 
      onLogout={handleLogout}
    >
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Icons } from '../constants';
import { authService } from '../services/authService';
import { User, Gender } from '../types';

interface ProfileEntryProps {
  onSuccess: (user: User) => void;
  onBack: () => void;
  redirectMessage?: string | null;
}

const ProfileEntry: React.FC<ProfileEntryProps> = ({ onSuccess, onBack, redirectMessage }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [gender, setGender] = useState<Gender | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError("Please enter your name.");
      return;
    }
    if (phone.length !== 10) {
      setError("Enter a 10-digit number.");
      return;
    }
    if (!gender) {
      setError("Please select your gender.");
      return;
    }

    setError('');
    setLoading(true);
    try {
      const user = await authService.saveProfile(name, phone, gender);
      onSuccess(user);
    } catch (err: any) {
      setError("Something went wrong. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col gap-10 animate-fadeIn py-8 px-2">
      {/* Header & Optional Redirect Message */}
      <div className="flex flex-col gap-3 text-center">
        {redirectMessage && (
          <div className="mb-4 p-4 bg-blue-500/5 border border-blue-500/20 rounded-2xl flex items-center justify-center gap-3 animate-slideDown">
             <span className="text-xl">✨</span>
             <p className="text-sm font-medium text-blue-300 leading-tight">
               {redirectMessage}
             </p>
          </div>
        )}
        <h2 className="text-4xl font-bold font-heading tracking-tight text-white">Let's Get Started</h2>
        <p className="text-slate-400 text-base">Enter your details to continue.</p>
      </div>

      <form onSubmit={handleSubmit} className="flex flex-col gap-8">
        {error && (
          <div className="bg-red-500/10 border border-red-500/50 text-red-400 p-4 rounded-2xl text-sm font-medium animate-shake text-center">
            {error}
          </div>
        )}

        {/* Name Input */}
        <div className="flex flex-col gap-2">
          <label className="text-xs uppercase font-bold text-slate-500 ml-1 tracking-widest">Full Name</label>
          <input
            type="text"
            required
            autoFocus
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full bg-slate-900 border-2 border-slate-800 rounded-2xl px-6 py-5 text-lg font-medium focus:outline-none focus:border-blue-500 transition-all text-white placeholder:text-slate-700 shadow-inner"
            placeholder="Rahul Sharma"
          />
        </div>

        {/* Phone Input */}
        <div className="flex flex-col gap-2">
          <label className="text-xs uppercase font-bold text-slate-500 ml-1 tracking-widest">Contact Number</label>
          <div className="relative">
            <span className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-500 font-bold text-lg">+91</span>
            <input
              type="tel"
              required
              maxLength={10}
              value={phone}
              onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
              className="w-full bg-slate-900 border-2 border-slate-800 rounded-2xl pl-16 pr-6 py-5 text-lg font-medium focus:outline-none focus:border-blue-500 transition-all text-white tracking-[0.2em] shadow-inner"
              placeholder="9876543210"
            />
          </div>
        </div>

        {/* Gender Selection */}
        <div className="flex flex-col gap-2">
          <label className="text-xs uppercase font-bold text-slate-500 ml-1 tracking-widest">Gender</label>
          <div className="flex gap-4 mt-1">
            {(['Male', 'Female'] as Gender[]).map((g) => (
              <button
                key={g}
                type="button"
                onClick={() => setGender(g)}
                className={`flex-1 py-5 rounded-2xl border-2 text-base font-bold transition-all flex items-center justify-center gap-2 ${
                  gender === g 
                    ? 'bg-blue-600 border-blue-400 text-white shadow-[0_0_20px_rgba(59,130,246,0.4)]' 
                    : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'
                }`}
              >
                {g}
              </button>
            ))}
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="w-full py-6 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold text-xl shadow-xl neon-glow-blue flex items-center justify-center gap-4 active:scale-95 transition-all mt-6"
        >
          {loading ? (
            <div className="w-6 h-6 border-3 border-white/20 border-t-white rounded-full animate-spin"></div>
          ) : (
            <>
              <span>Continue</span>
              <Icons.ArrowRight />
            </>
          )}
        </button>
      </form>

      <button
        onClick={onBack}
        className="text-xs font-bold text-slate-600 uppercase tracking-[0.3em] text-center hover:text-slate-400 transition-colors py-4"
      >
        Go Back
      </button>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }

        @keyframes slideDown {
          from { transform: translateY(-10px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .animate-slideDown { animation: slideDown 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
      `}</style>
    </div>
  );
};

export default ProfileEntry;

import React, { useState, useEffect, useRef } from 'react';
import { Icons } from '../constants';
import { generateDetailedRoadmap } from '../services/geminiService';
import { ProgressRing } from '../App';
import { User, RoadmapRecord } from '../types';
import { dbService } from '../services/dbService';

enum EngineState {
  INTRO,
  QUESTIONNAIRE,
  GENERATING,
  PREVIEW
}

const QUESTIONS = [
  { key: 'age', text: "Pehle apni age batao? (e.g. 21)" },
  { key: 'status', text: "Abhi kya kar rahe ho? (Student / Jobless / Working / Dropout)" },
  { key: 'device', text: "Kaam ke liye kya device hai? (Only Phone / Laptop / Both)" },
  { key: 'interest', text: "Kis cheez mein thoda interest hai? (Editing / Writing / AI / Social Media / Unsure)" },
  { key: 'goal', text: "Main goal kya hai? (Skill seekhna / First earning / Freelancing / Confidence)" }
];

interface RoadmapsProps {
  user: User | null;
  onAuthRequired: (message?: string) => void;
}

const Roadmaps: React.FC<RoadmapsProps> = ({ user, onAuthRequired }) => {
  const [state, setState] = useState<EngineState>(EngineState.INTRO);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [inputValue, setInputValue] = useState('');
  const [generatedData, setGeneratedData] = useState<any>(null);
  const [activeRoadmapRecord, setActiveRoadmapRecord] = useState<RoadmapRecord | null>(null);
  const [chatHistory, setChatHistory] = useState<{ role: 'ai' | 'user', text: string }[]>([]);
  const [generationStep, setGenerationStep] = useState(0);
  const [downloading, setDownloading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const steps = [
    "Analyzing profile data",
    "Mapping skills to interests",
    "Crafting 30-day curriculum",
    "Configuring earning modules",
    "Finalizing custom roadmap"
  ];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatHistory, state]);

  useEffect(() => {
    let interval: any;
    if (state === EngineState.GENERATING) {
      interval = setInterval(() => {
        setGenerationStep(prev => (prev < steps.length - 1 ? prev + 1 : prev));
      }, 1800);
    }
    return () => clearInterval(interval);
  }, [state]);

  const startEngine = () => {
    if (!user) {
      onAuthRequired("Roadmap dekhne ke liye pehle apni basic details bharo.");
      return;
    }
    setState(EngineState.QUESTIONNAIRE);
    setChatHistory([{ role: 'ai', text: QUESTIONS[0].text }]);
  };

  const handleAnswer = async () => {
    if (!inputValue.trim()) return;

    const currentKey = QUESTIONS[currentQuestionIndex].key;
    const newAnswers = { ...answers, [currentKey]: inputValue };
    setAnswers(newAnswers);

    const newHistory = [...chatHistory, { role: 'user' as const, text: inputValue }];
    setChatHistory(newHistory);
    setInputValue('');

    if (currentQuestionIndex < QUESTIONS.length - 1) {
      const nextIndex = currentQuestionIndex + 1;
      setCurrentQuestionIndex(nextIndex);
      setTimeout(() => {
        setChatHistory(prev => [...prev, { role: 'ai', text: QUESTIONS[nextIndex].text }]);
      }, 400);
    } else {
      setState(EngineState.GENERATING);
      setGenerationStep(0);
      const roadmap = await generateDetailedRoadmap(newAnswers);
      if (roadmap) {
        setGeneratedData(roadmap);
        // If logged in, save to DB immediately
        if (user) {
          const record = await dbService.saveRoadmap(user.id, roadmap);
          setActiveRoadmapRecord(record);
        }
        setState(EngineState.PREVIEW);
      } else {
        alert("Something went wrong. Please try again.");
        setState(EngineState.INTRO);
      }
    }
  };

  const handleDownloadPDF = async () => {
    if (!user) {
      onAuthRequired("Roadmap download karne ke liye pehle apni basic details bharo.");
      return;
    }

    setDownloading(true);

    try {
      // 1. Simulate API delay & Auth Check
      await new Promise(r => setTimeout(r, 1500));

      // 2. Prepare content for "Binary" response simulation
      const content = `
        SkillShift Roadmap: ${generatedData.skillName}
        Goal: ${generatedData.userGoal}
        Generated for: ${user.phone}
        Date: ${new Date().toLocaleDateString()}

        --- 30 DAY PLAN ---
        ${generatedData.dailyPlan.map((d: any) => `Day ${d.day}: ${d.title}\nTask: ${d.task}\n`).join('\n')}
      `;

      // 3. Create Binary Blob
      const blob = new Blob([content], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);

      // 4. Update PDF Metadata in "DB"
      if (activeRoadmapRecord) {
        await dbService.savePDFMetadata(
          activeRoadmapRecord.id, 
          `SkillShift_${generatedData.skillName.replace(/\s+/g, '_')}.pdf`,
          blob.size,
          'simulated_storage_path'
        );
      }

      // 5. Trigger Browser Download
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `SkillShift_Roadmap_${generatedData.skillName.replace(/\s+/g, '_')}.pdf`);
      document.body.appendChild(link);
      link.click();

      // Cleanup
      link.parentNode?.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Download failed:", err);
      alert("Download failed. Try again.");
    } finally {
      setDownloading(false);
    }
  };

  if (state === EngineState.INTRO) {
    return (
      <div className="flex flex-col gap-8 animate-fadeIn">
        <div className="flex flex-col gap-4 text-center">
          <div className="mx-auto w-16 h-16 rounded-3xl bg-blue-600/10 flex items-center justify-center text-blue-500 mb-2">
            <Icons.Map />
          </div>
          <h2 className="text-3xl font-bold font-heading">Roadmap Engine</h2>
          <p className="text-slate-400 text-sm leading-relaxed">
            Confused ho? Apna custom roadmap banao. <br/>
            Bas chhota sa questionnaire aur tera path ready.
          </p>
        </div>

        <button 
          onClick={startEngine}
          className="w-full py-5 bg-gradient-to-r from-blue-600 to-blue-700 rounded-2xl font-bold shadow-lg neon-glow-blue flex items-center justify-center gap-3 active:scale-95 transition-all"
        >
          <span>Start My Roadmap</span>
          <Icons.ArrowRight />
        </button>

        <div className="grid grid-cols-2 gap-4 mt-8">
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">🎯</div>
              <div className="text-[10px] font-bold text-slate-300">Personalized</div>
           </div>
           <div className="glass-card p-4 rounded-xl text-center border-slate-800">
              <div className="text-lg mb-1">📄</div>
              <div className="text-[10px] font-bold text-slate-300">Save as PDF</div>
           </div>
        </div>
      </div>
    );
  }

  if (state === EngineState.QUESTIONNAIRE) {
    return (
      <div className="flex flex-col h-[calc(100vh-220px)]">
        <div className="flex items-center gap-2 mb-4 text-slate-500">
           <button onClick={() => setState(EngineState.INTRO)} className="p-1"><div className="rotate-180"><Icons.ArrowRight /></div></button>
           <span className="text-xs font-bold uppercase tracking-wider">Step {currentQuestionIndex + 1} of 5</span>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fadeIn`}>
              <div className={`max-w-[85%] p-4 rounded-2xl text-sm ${
                msg.role === 'user' ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' : 'glass-card border-slate-800 text-slate-200 rounded-tl-none shadow-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-4 flex gap-2">
          <input 
            type="text" 
            autoFocus
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAnswer()}
            placeholder="Type your answer..."
            className="flex-1 bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-blue-500 transition-all text-white"
          />
          <button 
            onClick={handleAnswer}
            className="p-3 bg-blue-600 text-white rounded-xl shadow-lg active:scale-95 transition-all"
          >
            <Icons.ArrowRight />
          </button>
        </div>
      </div>
    );
  }

  if (state === EngineState.GENERATING) {
    return (
      <div className="flex flex-col items-center justify-center h-[calc(100vh-220px)] gap-10">
        <ProgressRing size="w-16 h-16" />
        <div className="text-center space-y-6">
          <h3 className="text-xl font-semibold text-white font-heading opacity-90 tracking-tight">Designing Roadmap</h3>
          <div className="flex flex-col gap-2">
            {steps.map((step, idx) => (
              <p key={idx} className={`text-[11px] uppercase tracking-widest font-medium transition-all duration-500 ${idx === generationStep ? 'text-blue-400' : idx < generationStep ? 'text-slate-500' : 'text-slate-800'}`}>
                {step}
              </p>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (state === EngineState.PREVIEW && generatedData) {
    return (
      <div className="flex flex-col animate-fadeIn">
        {/* Sticky Toolbar */}
        <div className="no-print sticky top-16 z-40 bg-slate-950/95 backdrop-blur-md py-4 border-b border-slate-800 -mx-5 px-5 mb-8 flex items-center justify-between">
           <button 
            onClick={() => setState(EngineState.INTRO)} 
            className="flex items-center gap-2 text-slate-500 text-xs font-bold uppercase tracking-widest hover:text-slate-300 transition-colors"
           >
             <div className="rotate-180 scale-75"><Icons.ArrowRight /></div> 
             Reset
           </button>
           <div className="flex items-center gap-2">
            <button 
              onClick={handleDownloadPDF} 
              disabled={downloading}
              className={`px-5 py-2.5 rounded-xl text-xs font-bold flex items-center gap-2 shadow-lg transition-all active:scale-95 bg-pink-600 text-white neon-glow-pink`}
            >
              {downloading ? (
                <div className="w-3 h-3 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
              ) : <Icons.Zap />}
              {downloading ? 'Preparing...' : 'Download Custom PDF'}
            </button>
           </div>
        </div>

        {/* Roadmap Content Header */}
        <div className="print-area glass-card rounded-[2.5rem] p-6 sm:p-8 border-blue-500/20 mb-20 relative overflow-hidden print:bg-white print:text-black print:p-12 print:border-none print:shadow-none print:max-w-none">
           {user && (
             <div className="absolute top-6 right-8 text-[8px] uppercase tracking-widest font-bold text-blue-500/40 no-print">
               Saved to Database
             </div>
           )}
           <div className="mb-16 text-center border-b border-slate-800/50 print:border-gray-200 pb-10 pt-4 animate-slideUp">
              <h1 className="text-3xl sm:text-4xl font-bold font-heading mb-4 text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-pink-500 leading-[1.2] print:text-black print:bg-none print:text-5xl uppercase tracking-tight break-words">
                {generatedData.skillName}
              </h1>
              <p className="text-slate-500 print:text-gray-500 text-[10px] font-bold uppercase tracking-[0.3em] mb-8">
                30-Day Custom Roadmap
              </p>

              <div className="p-5 bg-slate-900/60 rounded-3xl border border-slate-800 text-left print:bg-gray-50 print:border-gray-300">
                <div className="flex flex-col gap-4">
                  <div>
                    <span className="text-[10px] font-bold text-blue-500 uppercase tracking-[0.2em] block mb-2">Goal: {generatedData.userGoal}</span>
                    <p className="text-sm text-slate-200 print:text-black font-medium leading-relaxed italic">"{generatedData.whyThisSkill}"</p>
                  </div>
                </div>
              </div>
           </div>

           {/* 30-Day Plan Timeline */}
           <div className="space-y-16">
              {generatedData.dailyPlan.map((day: any, idx: number) => {
                const isWeeklyReview = (idx + 1) % 7 === 0;
                const weekNum = (idx + 1) / 7;
                const weekReview = generatedData.weeklyReview?.find((r: any) => r.week === weekNum);

                return (
                  <React.Fragment key={day.day}>
                    <div className="flex gap-6 sm:gap-8 relative group break-inside-avoid">
                      <div className="flex flex-col items-center">
                        <div className="w-12 h-12 sm:w-14 sm:h-14 rounded-2xl sm:rounded-3xl bg-slate-900 flex items-center justify-center font-bold text-blue-400 border border-slate-800 print:border-gray-400 print:text-black print:bg-gray-100 shadow-xl">
                          {day.day}
                        </div>
                        {idx !== generatedData.dailyPlan.length - 1 && <div className="w-px flex-1 bg-slate-800 my-4 print:bg-gray-200 opacity-50"></div>}
                      </div>

                      <div className="flex-1 pb-10">
                        <div className="flex items-start justify-between mb-4">
                           <h4 className="text-lg sm:text-xl font-bold text-white print:text-black leading-tight pr-4">{day.title}</h4>
                           <span className="text-[9px] bg-blue-500/10 text-blue-400 px-3 py-1 rounded-full border border-blue-500/20 font-bold print:bg-gray-100 print:text-black uppercase whitespace-nowrap">{day.timeMinutes}m</span>
                        </div>

                        <div className="space-y-6">
                          <div className="text-[13px] text-slate-400 print:text-gray-700 leading-relaxed">
                            <span className="text-blue-500 font-bold uppercase tracking-widest text-[8px] block mb-1">Concept</span> {day.learn}
                          </div>

                          <div className="p-5 bg-gradient-to-br from-blue-500/10 to-pink-500/5 rounded-2xl border border-blue-500/10 print:bg-gray-50 print:border-gray-200">
                            <span className="text-pink-500 font-bold uppercase tracking-widest text-[8px] block mb-2">Today's Mission</span>
                            <p className="text-[14px] text-slate-100 print:text-black font-semibold leading-relaxed">{day.task}</p>
                          </div>
                        </div>
                      </div>
                    </div>

                    {isWeeklyReview && weekReview && (
                       <div className="my-10 p-6 rounded-3xl bg-blue-600/5 border border-blue-500/10 break-inside-avoid print:bg-gray-100 print:border-gray-300 animate-fadeIn">
                          <h3 className="text-lg font-bold text-blue-400 mb-5 flex items-center gap-2 print:text-black">
                            <div className="p-1.5 bg-blue-500/10 rounded-lg"><Icons.Check /></div>
                            Week {weekReview.week} Reflection
                          </h3>
                       </div>
                    )}
                  </React.Fragment>
                );
              })}
           </div>

           {/* Earning Guide Section */}
           <div className="mt-20 p-8 sm:p-10 rounded-[2.5rem] bg-slate-950/50 border border-green-500/20 break-inside-avoid print:bg-gray-50 print:border-gray-300 print:text-black">
              <div className="flex items-center gap-5 mb-10">
                 <div className="w-16 h-16 rounded-2xl bg-green-500/10 flex items-center justify-center text-2xl text-green-500">💰</div>
                 <div>
                    <h3 className="text-2xl font-bold text-white print:text-black font-heading">First Earning</h3>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.2em]">Ready around Day {generatedData.firstEarningGuide.readyAfterDays}</p>
                 </div>
              </div>
           </div>

           {/* Disclaimer Footer */}
           <div className="mt-16 pt-12 text-center border-t border-slate-900/50 print:border-gray-200">
              <p className="text-lg font-medium text-slate-300 italic mb-10 max-w-lg mx-auto leading-relaxed print:text-black">
                "{generatedData.finalNote}"
              </p>
           </div>
        </div>

        <style>{`
          @media print {
            .no-print { display: none !important; }
            body { background: white !important; color: black !important; padding: 0 !important; margin: 0 !important; }
            #root { max-width: none !important; border: none !important; box-shadow: none !important; margin: 0 !important; width: 100% !important; }
            main { padding: 0 !important; overflow: visible !important; width: 100% !important; }
            .print-area { border: none !important; background: transparent !important; padding: 0 !important; width: 100% !important; margin: 0 !important; border-radius: 0 !important; }
            header, nav { display: none !important; }
            .break-inside-avoid { break-inside: avoid; }
            @page { margin: 1cm; size: A4; }
          }
          .custom-scrollbar::-webkit-scrollbar { width: 4px; }
          .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 4px; }

          @keyframes slideUp {
            from { transform: translateY(20px); opacity: 0; }
            to { transform: translateY(0); opacity: 1; }
          }
          .animate-slideUp { animation: slideUp 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        `}</style>
      </div>
    );
  }

  return null;
};

