  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [authRedirectMessage, setAuthRedirectMessage] = useState<string | null>(null);

  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }

    // Secret URL detection
    const path = window.location.pathname;
    if (path === '/admin-overview' || path === '/hidden-admin-panel') {
      setCurrentPage(Page.ADMIN_DASHBOARD);
    } else if (path === '/admin-daily-report') {
      setCurrentPage(Page.ADMIN_REPORT);
    } else if (path === '/admin-weekly-report') {
      setCurrentPage(Page.ADMIN_WEEKLY_REPORT);
    }

    const timer = setTimeout(() => setIsLoaded(true), 800);
    return () => clearTimeout(timer);
  }, []);

  const handlePageChange = (page: Page, message?: string) => {
    // Access control for roadmaps
    if (page === Page.ROADMAPS && !user) {
      setAuthRedirectMessage(message || "Roadmap dekhne ke liye pehle apni basic details bharo.");
      setCurrentPage(Page.PROFILE_ENTRY);
      return;
    }

    // Reset message if going elsewhere
    if (page !== Page.PROFILE_ENTRY) {
      setAuthRedirectMessage(null);
    }

    setCurrentPage(page);
  };

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
    // Reset path if in admin
    if (window.location.pathname.includes('admin')) {
      window.history.pushState({}, '', '/');
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME:
        return <Home onNavigate={handlePageChange} user={user} />;
      case Page.MENTOR:
        return <MentorChat />;
      case Page.FINDER:
        return <SkillFinder />;
      case Page.ROADMAPS:
        return (
          <Roadmaps 
            user={user} 
            onAuthRequired={(msg) => handlePageChange(Page.PROFILE_ENTRY, msg)} 
          />
        );
      case Page.BOOST:
        return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            redirectMessage={authRedirectMessage}
            onSuccess={(u) => {
              setUser(u);
              setAuthRedirectMessage(null);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => handlePageChange(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap 
            user={user} 
            onComplete={() => setCurrentPage(Page.ROADMAPS)} 
          />
        ) : <Home onNavigate={handlePageChange} user={null} />;
      case Page.ADMIN_DASHBOARD:
        return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT:
        return <AdminReport user={user} />;
      case Page.ADMIN_WEEKLY_REPORT:
        return <AdminWeeklyReport user={user} />;
      default:
        return <Home onNavigate={handlePageChange} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-3xl font-bold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <div className="flex gap-1.5">
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-100"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentPage={currentPage} 
      onPageChange={handlePageChange} 
      user={user} 
      onLogout={handleLogout}
    >
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
