}

const AdminMonthlyReport: React.FC<AdminMonthlyReportProps> = ({ user }) => {
  const WHATSAPP_NUMBER = "7991500823";
  const [reportSent, setReportSent] = useState(false);

  useEffect(() => {
    const lastSent = localStorage.getItem('skillshift_monthly_report_sent');
    if (lastSent) {
      const lastSentDate = new Date(lastSent);
      const now = new Date();
      // Check if sent in the same month
      if (lastSentDate.getMonth() === now.getMonth() && lastSentDate.getFullYear() === now.getFullYear()) {
        setReportSent(true);
      }
    }
  }, []);

  // Access Restriction Check
  if (!user || user.role !== 'admin') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center animate-fadeIn">
        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
