• New users joined: ${monthlyUsers.length}
• Most popular roadmap: ${topRoadmap}

Overall summary:
“Is month platform growth stable rahi aur users ne
${topRoadmap} ko sabse zyada prefer kiya.”
--------------------------------`;

    return {
      monthName,
      text: reportText,
      topRoadmap
    };
  }, []);

  const sendToWhatsApp = () => {
    const encodedText = encodeURIComponent(reportData.text);
    const url = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodedText}`;
    window.open(url, '_blank');

    // Mark as sent for this month
    localStorage.setItem('skillshift_monthly_report_sent', new Date().toISOString());
    setReportSent(true);
  };

  return (
    <div className="flex flex-col gap-6 animate-fadeIn py-8 px-2">
      <div className="flex flex-col gap-2 mb-4">
        <h2 className="text-2xl font-bold font-heading text-white">Monthly Report</h2>
        <p className="text-slate-500 text-sm">Review and share the performance of the entire month.</p>
      </div>

      {reportSent && (
        <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl flex items-center gap-3 text-blue-400 text-xs font-medium">
          <span>📅</span>
          Report for {reportData.monthName} has already been generated/sent.
        </div>
      )}

      <div className="glass-card rounded-3xl p-6 border-slate-800 font-mono text-sm whitespace-pre-wrap leading-relaxed text-slate-300">
        {reportData.text}
      </div>

      <div className="flex flex-col gap-3 mt-4">
        <button 
          onClick={sendToWhatsApp}
          className="w-full py-5 bg-[#25D366] text-white rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg hover:brightness-110 transition-all active:scale-95"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"/></svg>
