import { User } from "../types";

/**
 * IMPORTANT: Replace the URL below with your actual Google Apps Script Web App URL
 * after following the deployment instructions provided.
 */
const SHEET_SCRIPT_URL = "https://script.google.com/macros/s/AKfycbyN_EXAMPLE_ID/exec";

export const sheetService = {
  syncToGoogleSheet: async (user: User, roadmapName: string): Promise<{ success: boolean; error?: string }> => {
    try {
      if (SHEET_SCRIPT_URL.includes("EXAMPLE_ID")) {
        console.warn("Sheet Sync: Please configure your SHEET_SCRIPT_URL in services/sheetService.ts");
        return { success: false, error: "Script URL not configured" };
      }

      const payload = {
        name: user.name,
        contact: user.phone,
        gender: user.gender,
        roadmap: roadmapName
      };

      // We use fetch with 'no-cors' for Apps Script to ensure the request hits the server 
      // even if the browser blocks reading the response.
      await fetch(SHEET_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        cache: 'no-cache',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload)
      });

      // Since 'no-cors' is used, we assume success if no exception is thrown
      return { success: true };
    } catch (error) {
      console.error("Sheet Sync Failed:", error);
      return { success: false, error: String(error) };
    }
  }
};

