import { 
  signInWithPopup, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from "firebase/auth";
import { auth, googleProvider } from "../firebase";
import { User, Gender } from "../types";
import { dbService } from "./dbService";

const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  loginWithGoogle: async (): Promise<User> => {
    try {
      const result = await signInWithPopup(auth, googleProvider);
      const fbUser = result.user;

      const user = await dbService.createProfile(
        fbUser.displayName || "Anonymous", 
        fbUser.phoneNumber || "0000000000", 
        'Other'
      );

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return user;
    } catch (error: any) {
      console.error("Firebase Login Error Details:", error);
      if (error.code === 'auth/unauthorized-domain') {
        // Fallback to origin if hostname is empty (common in some mobile browsers/webviews)
        const detected = window.location.hostname || window.location.origin.replace(/^https?:\/\//, '');
        throw new Error(`AUTH_DOMAIN_ERROR:${detected || 'unknown'}`);
      }
      throw error;
    }
  },

  signUpWithEmail: async (email: string, pass: string, name: string, gender: Gender, phone: string): Promise<User> => {
    try {
      const result = await createUserWithEmailAndPassword(auth, email, pass);
      const user = await dbService.createProfile(name, phone, gender);
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return user;
    } catch (error: any) {
      if (error.code === 'auth/unauthorized-domain') {
        const detected = window.location.hostname || 'unknown';
        throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
      }
      throw error;
    }
  },

  signInWithEmail: async (email: string, pass: string): Promise<User> => {
    try {
      const result = await signInWithEmailAndPassword(auth, email, pass);
      const users = dbService.getAllUsers();
      const existing = users.find(u => u.name === result.user.displayName) || {
        id: result.user.uid,
        name: result.user.displayName || "User",
        phone: "0000000000",
        gender: "Other" as Gender,
        role: 'user',
        created_at: new Date().toISOString()
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(existing));
      return existing as User;
    } catch (error: any) {
      if (error.code === 'auth/unauthorized-domain') {
        const detected = window.location.hostname || 'unknown';
        throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
      }
      throw error;
    }
  },

  logout: async () => {
    await signOut(auth);
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  onAuthUpdate: (callback: (user: FirebaseUser | null) => void) => {
    return onAuthStateChanged(auth, callback);
  }
};

