import React, { useState, useEffect } from 'react';
import { Page, User } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';
import ProfileEntry from './pages/ProfileEntry';
import PreparingRoadmap from './pages/PreparingRoadmap';
import AdminDashboard from './pages/AdminDashboard';
import AdminReport from './pages/AdminReport';
import AdminWeeklyReport from './pages/AdminWeeklyReport';
import AdminMonthlyReport from './pages/AdminMonthlyReport';
import { authService } from './services/authService';

export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle className="opacity-10" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" />
      <circle className="text-blue-500" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" strokeDasharray="80" strokeDashoffset="60" strokeLinecap="round" />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [authRedirectMessage, setAuthRedirectMessage] = useState<string | null>(null);

  // Initialize App and Auth only once
  useEffect(() => {
    // 1. Sync local user from authService
    const currentUser = authService.getCurrentUser();
    if (currentUser) setUser(currentUser);

    // 2. Subscribe to Firebase Auth changes
    const unsubscribe = authService.onAuthUpdate((fbUser) => {
      if (!fbUser) {
        // Only reset if they were previously logged in
        setUser(prev => {
          if (prev) {
            setCurrentPage(Page.HOME);
            return null;
          }
          return prev;
        });
      }
    });

    // 3. Secret URL detection
    const path = window.location.pathname;
    if (path === '/admin-overview' || path === '/hidden-admin-panel') {
      setCurrentPage(Page.ADMIN_DASHBOARD);
    } else if (path === '/admin-daily-report') {
      setCurrentPage(Page.ADMIN_REPORT);
    } else if (path === '/admin-weekly-report') {
      setCurrentPage(Page.ADMIN_WEEKLY_REPORT);
    } else if (path === '/admin-monthly-report') {
      setCurrentPage(Page.ADMIN_MONTHLY_REPORT);
    }

    // 4. Force loading to end
    const timer = setTimeout(() => setIsLoaded(true), 1200);

    return () => {
      clearTimeout(timer);
      unsubscribe();
    };
  }, []); // Empty dependency array is critical to stop the loop

  const handlePageChange = (page: Page, message?: string) => {
    if (page === Page.ROADMAPS && !user) {
      setAuthRedirectMessage(message || "Roadmap dekhne ke liye pehle login karo.");
      setCurrentPage(Page.PROFILE_ENTRY);
      return;
    }
    if (page !== Page.PROFILE_ENTRY) setAuthRedirectMessage(null);
    setCurrentPage(page);
  };

  const handleLogout = async () => {
    await authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
    if (window.location.pathname.includes('admin')) {
      window.history.pushState({}, '', '/');
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <Home onNavigate={handlePageChange} user={user} />;
      case Page.MENTOR: return <MentorChat />;
      case Page.FINDER: return <SkillFinder />;
      case Page.ROADMAPS: return <Roadmaps user={user} onAuthRequired={(msg) => handlePageChange(Page.PROFILE_ENTRY, msg)} />;
      case Page.BOOST: return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            redirectMessage={authRedirectMessage}
            onSuccess={(u) => {
              setUser(u);
              setAuthRedirectMessage(null);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => handlePageChange(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap user={user} onComplete={() => setCurrentPage(Page.ROADMAPS)} />
        ) : <Home onNavigate={handlePageChange} user={null} />;
      case Page.ADMIN_DASHBOARD: return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT: return <AdminReport user={user} />;
      case Page.ADMIN_WEEKLY_REPORT: return <AdminWeeklyReport user={user} />;
      case Page.ADMIN_MONTHLY_REPORT: return <AdminMonthlyReport user={user} />;
      default: return <Home onNavigate={handlePageChange} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-3xl font-bold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <div className="flex gap-1.5 text-blue-500">
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce delay-100"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout currentPage={currentPage} onPageChange={handlePageChange} user={user} onLogout={handleLogout}>
      {renderPage()}
    </Layout>
  );
};

export default App;

import { 
  signInWithPopup, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from "firebase/auth";
import { auth, googleProvider } from "../firebase";
import { User, Gender } from "../types";
import { dbService } from "./dbService";

const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  loginWithGoogle: async (): Promise<User> => {
    try {
      const result = await signInWithPopup(auth, googleProvider);
      const fbUser = result.user;

      const user = await dbService.createProfile(
        fbUser.displayName || "Anonymous", 
        fbUser.phoneNumber || "0000000000", 
        'Other'
      );

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return user;
    } catch (error: any) {
      console.error("Firebase Auth Error Object:", error);
      if (error.code === 'auth/unauthorized-domain' || error.message?.includes('unauthorized domain')) {
        const detected = window.location.hostname || window.location.host || "skillshift-app";
        throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
      }
      throw error;
    }
  },

  signUpWithEmail: async (email: string, pass: string, name: string, gender: Gender, phone: string): Promise<User> => {
    try {
      const result = await createUserWithEmailAndPassword(auth, email, pass);
      const user = await dbService.createProfile(name, phone, gender);
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return user;
    } catch (error: any) {
      if (error.code === 'auth/unauthorized-domain') {
        const detected = window.location.hostname || "skillshift-app";
        throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
      }
      throw error;
    }
  },

  signInWithEmail: async (email: string, pass: string): Promise<User> => {
    try {
      const result = await signInWithEmailAndPassword(auth, email, pass);
      const users = dbService.getAllUsers();
      const existing = users.find(u => u.name === result.user.displayName) || {
        id: result.user.uid,
        name: result.user.displayName || "User",
        phone: "0000000000",
        gender: "Other" as Gender,
        role: 'user',
        created_at: new Date().toISOString()
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(existing));
      return existing as User;
    } catch (error: any) {
      if (error.code === 'auth/unauthorized-domain') {
        const detected = window.location.hostname || "skillshift-app";
        throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
      }
      throw error;
    }
  },

  logout: async () => {
    await signOut(auth);
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  onAuthUpdate: (callback: (user: FirebaseUser | null) => void) => {
    return onAuthStateChanged(auth, callback);
  }
};

import { 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where, 
  addDoc, 
  orderBy, 
  limit, 
  Timestamp,
  serverTimestamp 
} from "firebase/firestore";
import { db } from "../firebase";
import { RoadmapRecord, User, Gender } from "../types";

const ADMIN_PHONES = ["7991500823", "9991234567", "9876543210"];

export const dbService = {
  // Cloud Profile Creation/Sync
  createProfile: async (name: string, phone: string, gender: Gender): Promise<User> => {
    const usersRef = collection(db, "users");
    // Optimized search by phone
    const q = query(usersRef, where("phone", "==", phone), limit(1));
    const querySnapshot = await getDocs(q);

    if (!querySnapshot.empty) {
      const existingData = querySnapshot.docs[0].data() as User;
      return { ...existingData, id: querySnapshot.docs[0].id };
    }

    const newUser: any = {
      name,
      phone,
      gender,
      role: ADMIN_PHONES.includes(phone) ? 'admin' : 'user',
      created_at: new Date().toISOString()
    };

    const docRef = await addDoc(collection(db, "users"), newUser);
    return { ...newUser, id: docRef.id };
  },

  // Optimized for 1 Lakh users - Fetch only recent data
  getGlobalStats: async () => {
    // For 100k users, we fetch limited recent data for dashboard UI
    const usersQuery = query(collection(db, "users"), orderBy("created_at", "desc"), limit(50));
    const roadmapsQuery = query(collection(db, "roadmaps"), orderBy("created_at", "desc"), limit(50));

    const [usersSnap, roadmapsSnap] = await Promise.all([
      getDocs(usersQuery),
      getDocs(roadmapsQuery)
    ]);

    // Note: In a real production 100k app, "Total Count" should be read from an aggregation document
    // For now, we return the counts based on recent trends
    return {
      recentUsers: usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User)),
      recentRoadmaps: roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord)),
      // We simulate total counts as Firebase Firestore doesn't provide a cheap 'count' for 100k records without aggregation docs
      isScaling: true
    };
  },

  // Optimized report fetch - Last 24 hours only
  getRecentActivity: async (days: number = 1): Promise<{users: User[], roadmaps: RoadmapRecord[]}> => {
    const timeLimit = new Date();
    timeLimit.setDate(timeLimit.getDate() - days);

    const uQuery = query(collection(db, "users"), where("created_at", ">=", timeLimit.toISOString()), limit(500));
    const rQuery = query(collection(db, "roadmaps"), where("created_at", ">=", timeLimit.toISOString()), limit(500));

    const [uSnap, rSnap] = await Promise.all([getDocs(uQuery), getDocs(rQuery)]);

    return {
      users: uSnap.docs.map(d => ({ ...d.data(), id: d.id } as User)),
      roadmaps: rSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord))
    };
  },

  getAllUsers: async (limitCount: number = 100): Promise<User[]> => {
    const q = query(collection(db, "users"), orderBy("created_at", "desc"), limit(limitCount));
    const usersSnap = await getDocs(q);
    return usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User));
  },

  getAllRoadmaps: async (limitCount: number = 100): Promise<RoadmapRecord[]> => {
    const q = query(collection(db, "roadmaps"), orderBy("created_at", "desc"), limit(limitCount));
    const roadmapsSnap = await getDocs(q);
    return roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord));
  },

  // Save Roadmap to Cloud
  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const newRecord: any = {
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };

    const docRef = await addDoc(collection(db, "roadmaps"), newRecord);
    return { ...newRecord, id: docRef.id };
  },

  // Get User's Roadmaps
  getRoadmapsByUserId: async (user_id: string): Promise<RoadmapRecord[]> => {
    const q = query(collection(db, "roadmaps"), where("user_id", "==", user_id), orderBy("created_at", "desc"), limit(10));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as RoadmapRecord));
  }
};

