import React, { useMemo, useState, useEffect } from 'react';
import { dbService } from '../services/dbService';
import { User, RoadmapRecord } from '../types';

interface AdminReportProps {
  user: User | null;
}

const AdminReport: React.FC<AdminReportProps> = ({ user }) => {
  const [data, setData] = useState<{users: User[], roadmaps: RoadmapRecord[]} | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      if (user?.role === 'admin') {
        try {
          // Optimized: Only fetching today's activity from server
          const activity = await dbService.getRecentActivity(1);
          setData(activity);
        } catch (error) {
          console.error("Report data fetch failed:", error);
        } finally {
          setLoading(false);
        }
      }
    };
    fetchData();
  }, [user]);

  if (!user || user.role !== 'admin') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center text-red-500 mb-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="11" x="3" y="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
        </div>
        <h2 className="text-2xl font-bold font-heading text-white mb-2">Access Restricted</h2>
      </div>
    );
  }

  const reportData = useMemo(() => {
    if (!data) return null;

    const roadmapCounts: Record<string, number> = {};
    data.roadmaps.forEach(rm => {
      roadmapCounts[rm.skill_name] = (roadmapCounts[rm.skill_name] || 0) + 1;
    });

    const sortedRoadmaps = Object.entries(roadmapCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    const maleCount = data.users.filter(u => u.gender === 'Male').length;
    const femaleCount = data.users.filter(u => u.gender === 'Female').length;

    return {
      date: new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' }),
      totalUsers: data.users.length,
      totalRoadmaps: data.roadmaps.length,
      topRoadmaps: sortedRoadmaps,
      male: maleCount,
      female: femaleCount,
      insight: sortedRoadmaps[0] ? `User interest is peaking in ${sortedRoadmaps[0][0]}.` : "Collecting initial data..."
    };
  }, [data]);

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[40vh] gap-4">
        <div className="w-8 h-8 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
        <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest">Compiling Edge Logs...</p>
      </div>
    );
  }

  if (!reportData) return null;

  return (
    <div className="flex flex-col gap-6 animate-fadeIn py-8 px-2 font-mono text-xs leading-relaxed text-slate-400">
      <div className="border-b border-slate-800 pb-4 mb-4">
        <h2 className="text-xl font-bold text-white mb-1 font-heading">Daily Scale Report</h2>
        <p className="text-slate-600 uppercase tracking-widest font-black text-[9px]">Status: Systems Operational</p>
      </div>

      <div className="space-y-6">
        <section>
          <div className="text-slate-600 mb-1">LOG_DATE: {reportData.date}</div>
          <div className="text-white font-bold mb-4">--------------------------------</div>

          <ul className="list-none space-y-1">
            <li>[+] NEW_USERS_24H: {reportData.totalUsers}</li>
            <li>[+] NEW_ROADMAPS_24H: {reportData.totalRoadmaps}</li>
          </ul>
        </section>

        <section>
          <div className="text-white font-bold mb-2 uppercase tracking-tighter">Market_Sentiment:</div>
          <ol className="list-none space-y-1">
            {reportData.topRoadmaps.map(([name, count], i) => (
              <li key={i}>{i + 1}) {name.padEnd(20, '.')} {count} HIT</li>
            ))}
          </ol>
        </section>

        <section>
          <div className="text-white font-bold mb-2 uppercase tracking-tighter">User_Demographics:</div>
          <ul className="list-none space-y-1">
            <li>• SEGMENT_MALE: {reportData.male}</li>
            <li>• SEGMENT_FEMALE: {reportData.female}</li>
          </ul>
          <div className="text-white font-bold mt-4">--------------------------------</div>
        </section>

        <section className="pt-4 italic text-blue-500/80">
          “ANALYSIS: {reportData.insight}”
        </section>
      </div>

      <div className="mt-12 text-center no-print">
        <button 
          onClick={() => window.print()}
          className="px-6 py-2 bg-slate-900 border border-slate-800 rounded-full text-[9px] uppercase tracking-[0.2em] font-black text-slate-500 hover:text-white transition-all"
        >
          Print System Log
        </button>
      </div>
    </div>
  );
};

export default AdminReport;

import { 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where, 
  addDoc, 
  orderBy, 
  limit, 
  Timestamp,
  serverTimestamp,
  getCountFromServer
} from "firebase/firestore";
import { db } from "../firebase";
import { RoadmapRecord, User, Gender } from "../types";

const ADMIN_PHONES = ["7991500823", "9991234567", "9876543210"];

export const dbService = {
  // Cloud Profile Creation/Sync
  createProfile: async (name: string, phone: string, gender: Gender): Promise<User> => {
    const usersRef = collection(db, "users");
    // Optimized search by phone with limit 1
    const q = query(usersRef, where("phone", "==", phone), limit(1));
    const querySnapshot = await getDocs(q);

    if (!querySnapshot.empty) {
      const existingData = querySnapshot.docs[0].data() as User;
      return { ...existingData, id: querySnapshot.docs[0].id };
    }

    const newUser: any = {
      name,
      phone,
      gender,
      role: ADMIN_PHONES.includes(phone) ? 'admin' : 'user',
      created_at: new Date().toISOString()
    };

    const docRef = await addDoc(collection(db, "users"), newUser);
    return { ...newUser, id: docRef.id };
  },

  // HIGH SCALE OPTIMIZATION: Use getCountFromServer instead of fetching all docs
  getGlobalStats: async () => {
    const usersColl = collection(db, "users");
    const roadmapsColl = collection(db, "roadmaps");

    // Aggregation queries are extremely efficient for 100k+ records
    const [usersCount, roadmapsCount] = await Promise.all([
      getCountFromServer(usersColl),
      getCountFromServer(roadmapsColl)
    ]);

    // Fetch only the most recent 50 for the activity stream
    const recentUsersQuery = query(usersColl, orderBy("created_at", "desc"), limit(50));
    const recentRoadmapsQuery = query(roadmapsColl, orderBy("created_at", "desc"), limit(50));

    const [usersSnap, roadmapsSnap] = await Promise.all([
      getDocs(recentUsersQuery),
      getDocs(recentRoadmapsQuery)
    ]);

    return {
      totalUsers: usersCount.data().count,
      totalRoadmaps: roadmapsCount.data().count,
      recentUsers: usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User)),
      recentRoadmaps: roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord)),
      isScaling: true
    };
  },

  // Optimized report fetch - filters server-side by date
  getRecentActivity: async (days: number = 1): Promise<{users: User[], roadmaps: RoadmapRecord[]}> => {
    const timeLimit = new Date();
    timeLimit.setDate(timeLimit.getDate() - days);
    const timeStr = timeLimit.toISOString();

    const uQuery = query(
      collection(db, "users"), 
      where("created_at", ">=", timeStr),
      limit(500) // Cap for safety
    );
    const rQuery = query(
      collection(db, "roadmaps"), 
      where("created_at", ">=", timeStr),
      limit(500)
    );

    const [uSnap, rSnap] = await Promise.all([getDocs(uQuery), getDocs(rQuery)]);

    return {
      users: uSnap.docs.map(d => ({ ...d.data(), id: d.id } as User)),
      roadmaps: rSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord))
    };
  },

  // Never fetch everything. Always limit for 100k user support.
  getAllUsers: async (limitCount: number = 50): Promise<User[]> => {
    const q = query(collection(db, "users"), orderBy("created_at", "desc"), limit(limitCount));
    const usersSnap = await getDocs(q);
    return usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User));
  },

  getAllRoadmaps: async (limitCount: number = 50): Promise<RoadmapRecord[]> => {
    const q = query(collection(db, "roadmaps"), orderBy("created_at", "desc"), limit(limitCount));
    const roadmapsSnap = await getDocs(q);
    return roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord));
  },

  // Save Roadmap to Cloud
  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const newRecord: any = {
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };

    const docRef = await addDoc(collection(db, "roadmaps"), newRecord);
    return { ...newRecord, id: docRef.id };
  },

  // Get User's Roadmaps (limited to 10 most recent)
  getRoadmapsByUserId: async (user_id: string): Promise<RoadmapRecord[]> => {
    const q = query(collection(db, "roadmaps"), where("user_id", "==", user_id), orderBy("created_at", "desc"), limit(10));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as RoadmapRecord));
  }
};

