import { 
  signInWithPopup, 
  signInWithRedirect,
  getRedirectResult,
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from "firebase/auth";
import { auth, googleProvider } from "../firebase";
import { User, Gender } from "../types";
import { dbService } from "./dbService";

const SESSION_KEY = 'skillshift_current_user';

const handleAuthError = (error: any) => {
  console.error("Firebase Auth Error Full Object:", error);
  const errorCode = error.code || 'unknown-error';

  if (errorCode === 'auth/unauthorized-domain' || 
      error.message?.toLowerCase().includes('unauthorized domain')) {
    const detected = window.location.hostname;
    throw new Error(`AUTH_DOMAIN_ERROR:${detected}`);
  }

  // Return the specific error code to show the user
  throw new Error(`AUTH_FAILED:${errorCode}`);
};

export const authService = {
  loginWithGoogle: async (): Promise<void> => {
    try {
      // Use Redirect instead of Popup for 100% mobile success
      await signInWithRedirect(auth, googleProvider);
    } catch (error: any) {
      handleAuthError(error);
    }
  },

  handleRedirectResult: async (): Promise<User | null> => {
    try {
      const result = await getRedirectResult(auth);
      if (result) {
        const fbUser = result.user;
        const user = await dbService.createProfile(
          fbUser.displayName || "Anonymous", 
          fbUser.phoneNumber || "0000000000", 
          'Other'
        );
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        return user;
      }
      return null;
    } catch (error: any) {
      handleAuthError(error);
      return null;
    }
  },

  signUpWithEmail: async (email: string, pass: string, name: string, gender: Gender, phone: string): Promise<User> => {
    try {
      const result = await createUserWithEmailAndPassword(auth, email, pass);
      const user = await dbService.createProfile(name, phone, gender);
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return user;
    } catch (error: any) {
      return handleAuthError(error);
    }
  },

  signInWithEmail: async (email: string, pass: string): Promise<User> => {
    try {
      const result = await signInWithEmailAndPassword(auth, email, pass);
      const users = await dbService.getAllUsers();
      const existing = users.find(u => u.name === result.user.displayName) || {
        id: result.user.uid,
        name: result.user.displayName || "User",
        phone: "0000000000",
        gender: "Other" as Gender,
        role: 'user',
        created_at: new Date().toISOString()
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(existing));
      return existing as User;
    } catch (error: any) {
      return handleAuthError(error);
    }
  },

  logout: async () => {
    await signOut(auth);
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  onAuthUpdate: (callback: (user: FirebaseUser | null) => void) => {
    return onAuthStateChanged(auth, callback);
  }
};

import React, { useState, useEffect } from 'react';
import { Page, User } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';
import ProfileEntry from './pages/ProfileEntry';
import PreparingRoadmap from './pages/PreparingRoadmap';
import AdminDashboard from './pages/AdminDashboard';
import AdminReport from './pages/AdminReport';
import AdminWeeklyReport from './pages/AdminWeeklyReport';
import AdminMonthlyReport from './pages/AdminMonthlyReport';
import { authService } from './services/authService';

export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle className="opacity-10" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" />
      <circle className="text-blue-500" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" strokeDasharray="80" strokeDashoffset="60" strokeLinecap="round" />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [authRedirectMessage, setAuthRedirectMessage] = useState<string | null>(null);

  // Initialize App and Auth only once
  useEffect(() => {
    const initAuth = async () => {
      // 1. Check for redirect result (Google Login completion)
      try {
        const redirectedUser = await authService.handleRedirectResult();
        if (redirectedUser) {
          setUser(redirectedUser);
          setCurrentPage(Page.PREPARING);
        }
      } catch (err) {
        console.error("Redirect Error:", err);
      }

      // 2. Sync local user from authService
      const currentUser = authService.getCurrentUser();
      if (currentUser) setUser(currentUser);

      // 3. Subscribe to Firebase Auth changes
      const unsubscribe = authService.onAuthUpdate((fbUser) => {
        if (!fbUser) {
          setUser(prev => {
            if (prev) {
              setCurrentPage(Page.HOME);
              return null;
            }
            return prev;
          });
        }
      });

      // 4. Secret URL detection
      const path = window.location.pathname;
      if (path === '/admin-overview' || path === '/hidden-admin-panel') {
        setCurrentPage(Page.ADMIN_DASHBOARD);
      } else if (path === '/admin-daily-report') {
        setCurrentPage(Page.ADMIN_REPORT);
      } else if (path === '/admin-weekly-report') {
        setCurrentPage(Page.ADMIN_WEEKLY_REPORT);
      } else if (path === '/admin-monthly-report') {
        setCurrentPage(Page.ADMIN_MONTHLY_REPORT);
      }

      // 5. Force loading to end
      setIsLoaded(true);
      return unsubscribe;
    };

    const unsubscribePromise = initAuth();

    return () => {
      unsubscribePromise.then(unsub => unsub?.());
    };
  }, []); 

  const handlePageChange = (page: Page, message?: string) => {
    if (page === Page.ROADMAPS && !user) {
      setAuthRedirectMessage(message || "Roadmap dekhne ke liye pehle login karo.");
      setCurrentPage(Page.PROFILE_ENTRY);
      return;
    }
    if (page !== Page.PROFILE_ENTRY) setAuthRedirectMessage(null);
    setCurrentPage(page);
  };

  const handleLogout = async () => {
    await authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
    if (window.location.pathname.includes('admin')) {
      window.history.pushState({}, '', '/');
    }
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <Home onNavigate={handlePageChange} user={user} />;
      case Page.MENTOR: return <MentorChat />;
      case Page.FINDER: return <SkillFinder />;
      case Page.ROADMAPS: return <Roadmaps user={user} onAuthRequired={(msg) => handlePageChange(Page.PROFILE_ENTRY, msg)} />;
      case Page.BOOST: return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            redirectMessage={authRedirectMessage}
            onSuccess={(u) => {
              setUser(u);
              setAuthRedirectMessage(null);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => handlePageChange(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap user={user} onComplete={() => setCurrentPage(Page.ROADMAPS)} />
        ) : <Home onNavigate={handlePageChange} user={null} />;
      case Page.ADMIN_DASHBOARD: return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT: return <AdminReport user={user} />;
      case Page.ADMIN_WEEKLY_REPORT: return <AdminWeeklyReport user={user} />;
      case Page.ADMIN_MONTHLY_REPORT: return <AdminMonthlyReport user={user} />;
      default: return <Home onNavigate={handlePageChange} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center gap-6 z-[100]">
        <ProgressRing size="w-16 h-16" />
        <div className="flex flex-col items-center gap-2">
          <h1 className="text-3xl font-bold font-heading tracking-tight text-white opacity-90">SkillShift</h1>
          <div className="flex gap-1.5 text-blue-500">
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce delay-100"></div>
             <div className="w-1.5 h-1.5 rounded-full bg-current animate-bounce delay-200"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout currentPage={currentPage} onPageChange={handlePageChange} user={user} onLogout={handleLogout}>
      {renderPage()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Icons } from '../constants';
import { authService } from '../services/authService';
import { User, Gender } from '../types';

interface ProfileEntryProps {
  onSuccess: (user: User) => void;
  onBack: () => void;
  redirectMessage?: string | null;
}

const ProfileEntry: React.FC<ProfileEntryProps> = ({ onSuccess, onBack, redirectMessage }) => {
  const [mode, setMode] = useState<'CHOICE' | 'EMAIL_SIGNUP' | 'EMAIL_LOGIN'>('CHOICE');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [phone, setPhone] = useState('');
  const [gender, setGender] = useState<Gender | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [unauthorizedDomain, setUnauthorizedDomain] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState(false);

  const handleGoogleLogin = async () => {
    setLoading(true);
    setError('');
    setUnauthorizedDomain(null);
    try {
      // Redirect logic: The response will be handled in App.tsx
      await authService.loginWithGoogle();
    } catch (err: any) {
      if (err.message.startsWith("AUTH_DOMAIN_ERROR:")) {
        const domain = err.message.split(":")[1];
        setUnauthorizedDomain(domain);
        setError(`Naya domain whitelist karna padega.`);
      } else if (err.message.startsWith("AUTH_FAILED:")) {
        const code = err.message.split(":")[1];
        setError(`Login Failed: ${code}. Please open in Chrome/Safari.`);
      } else {
        setError("Something went wrong. Use Chrome or Safari.");
      }
      setLoading(false);
    }
  };

  const handleEmailAction = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setUnauthorizedDomain(null);
    try {
      if (mode === 'EMAIL_SIGNUP') {
        if (!gender) throw new Error("Select gender");
        if (phone.length !== 10) throw new Error("Enter 10-digit phone");
        const user = await authService.signUpWithEmail(email, password, name, gender, phone);
        onSuccess(user);
      } else {
        const user = await authService.signInWithEmail(email, password);
        onSuccess(user);
      }
    } catch (err: any) {
      if (err.message.startsWith("AUTH_DOMAIN_ERROR:")) {
        const domain = err.message.split(":")[1];
        setUnauthorizedDomain(domain);
        setError(`Domain authorization needed.`);
      } else if (err.message.startsWith("AUTH_FAILED:")) {
        const code = err.message.split(":")[1];
        setError(`Auth Error: ${code}`);
      } else {
        setError(err.message || "Auth failed.");
      }
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = () => {
    if (unauthorizedDomain) {
      navigator.clipboard.writeText(unauthorizedDomain);
      setCopySuccess(true);
      setTimeout(() => setCopySuccess(false), 2000);
    }
  };

  return (
    <div className="flex flex-col gap-10 animate-fadeIn py-8 px-2">
      <div className="flex flex-col gap-3 text-center">
        {redirectMessage && (
          <div className="mb-4 p-4 bg-blue-500/5 border border-blue-500/20 rounded-2xl flex items-center justify-center gap-3 animate-slideDown">
             <span className="text-xl">✨</span>
             <p className="text-sm font-medium text-blue-300 leading-tight">{redirectMessage}</p>
          </div>
        )}
        <h2 className="text-4xl font-bold font-heading tracking-tight text-white">
          {mode === 'CHOICE' ? "Join SkillShift" : mode === 'EMAIL_SIGNUP' ? "Create Account" : "Welcome Back"}
        </h2>
        <p className="text-slate-400 text-base">Your future starts with one click.</p>
      </div>

      {error && !unauthorizedDomain && (
        <div className="bg-red-500/10 border border-red-500/50 text-red-400 p-4 rounded-2xl text-[11px] font-bold animate-shake text-center leading-relaxed">
          {error}
        </div>
      )}

      {unauthorizedDomain && (
        <div className="bg-slate-900 border border-slate-800 p-6 rounded-[2rem] flex flex-col gap-4 shadow-2xl animate-fadeIn">
          <div className="flex items-center justify-between">
             <span className="text-[10px] text-slate-500 uppercase font-black tracking-widest">Action Required</span>
             <button onClick={() => window.location.reload()} className="text-[10px] text-blue-400 font-bold uppercase underline">Refresh</button>
          </div>
          <p className="text-xs text-slate-300 leading-relaxed">
            Aapne URL change kiya hai. Is naye URL ko Firebase Console mein whitelist karna hoga:
          </p>
          <div className="bg-slate-950 p-4 rounded-2xl border border-slate-800 font-mono text-xs text-pink-400 break-all text-center">
            {unauthorizedDomain}
          </div>
          <button 
            onClick={copyToClipboard}
            className={`w-full py-4 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2 ${
              copySuccess ? 'bg-green-600 text-white' : 'bg-blue-600 text-white'
            }`}
          >
            {copySuccess ? 'Copied!' : 'Copy New URL'}
            {!copySuccess && <Icons.Check />}
