import { 
  collection, 
  getDocs, 
  query, 
  where, 
  addDoc, 
  setDoc,
  doc,
  getDoc,
  orderBy, 
  limit
} from "firebase/firestore";
import { db } from "../firebase";
import { RoadmapRecord, User, Gender } from "../types";

const ADMIN_PHONES = ["7991500823", "9991234567", "9876543210"];

export const dbService = {
  getUserProfile: async (uid: string): Promise<User | null> => {
    try {
      const docRef = doc(db, "users", uid);
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) {
        return { ...docSnap.data(), id: docSnap.id } as User;
      }
      return null;
    } catch (error) {
      console.error("DB Error: getUserProfile:", error);
      return null;
    }
  },

  createProfile: async (uid: string, name: string, phone: string, gender: Gender): Promise<User> => {
    try {
      const existing = await dbService.getUserProfile(uid);
      if (existing) return existing;

      const newUser: any = {
        name: name || "Anonymous",
        phone: phone || "0000000000",
        gender: gender || "Other",
        role: (phone && ADMIN_PHONES.includes(phone)) ? 'admin' : 'user',
        created_at: new Date().toISOString()
      };

      await setDoc(doc(db, "users", uid), newUser);
      return { ...newUser, id: uid };
    } catch (error) {
      console.error("DB Error: createProfile:", error);
      // Fallback stub to prevent auth blocking
      return {
        id: uid,
        name: name || "User",
        phone: phone || "0000000000",
        gender: gender || "Other",
        role: 'user',
        created_at: new Date().toISOString()
      };
    }
  },

  getGlobalStats: async () => {
    try {
      const usersSnap = await getDocs(collection(db, "users"));
      const roadmapsSnap = await getDocs(collection(db, "roadmaps"));

      const users = usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User));
      const roadmaps = roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord));

      return {
        totalUsers: users.length,
        totalRoadmaps: roadmaps.length,
        recentUsers: users.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()).slice(0, 50),
        recentRoadmaps: roadmaps.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()).slice(0, 50)
      };
    } catch (e) {
      return { totalUsers: 0, totalRoadmaps: 0, recentUsers: [], recentRoadmaps: [] };
    }
  },

  getRecentActivity: async (days: number = 1): Promise<{users: User[], roadmaps: RoadmapRecord[]}> => {
    try {
      const timeLimit = new Date();
      timeLimit.setDate(timeLimit.getDate() - days);
      const timeStr = timeLimit.toISOString();

      const uSnap = await getDocs(query(collection(db, "users"), where("created_at", ">=", timeStr)));
      const rSnap = await getDocs(query(collection(db, "roadmaps"), where("created_at", ">=", timeStr)));

      return {
        users: uSnap.docs.map(d => ({ ...d.data(), id: d.id } as User)),
        roadmaps: rSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord))
      };
    } catch (e) {
      return { users: [], roadmaps: [] };
    }
  },

  getAllUsers: async (): Promise<User[]> => {
    try {
      const usersSnap = await getDocs(query(collection(db, "users"), orderBy("created_at", "desc")));
      return usersSnap.docs.map(d => ({ ...d.data(), id: d.id } as User));
    } catch (e) { return []; }
  },

  getAllRoadmaps: async (): Promise<RoadmapRecord[]> => {
    try {
      const roadmapsSnap = await getDocs(query(collection(db, "roadmaps"), orderBy("created_at", "desc")));
      return roadmapsSnap.docs.map(d => ({ ...d.data(), id: d.id } as RoadmapRecord));
    } catch (e) { return []; }
  },

  saveRoadmap: async (user_id: string, roadmapData: any): Promise<RoadmapRecord> => {
    const newRecord: any = {
      user_id,
      skill_name: roadmapData.skillName,
      user_goal: roadmapData.userGoal,
      overview: roadmapData.overview || '',
      ai_json: roadmapData,
      created_at: new Date().toISOString()
    };

    const docRef = await addDoc(collection(db, "roadmaps"), newRecord);
    return { ...newRecord, id: docRef.id };
  },

  getRoadmapsByUserId: async (user_id: string): Promise<RoadmapRecord[]> => {
    try {
      const q = query(collection(db, "roadmaps"), where("user_id", "==", user_id), orderBy("created_at", "desc"), limit(10));
      const querySnapshot = await getDocs(q);
      return querySnapshot.docs.map(doc => ({ ...doc.data(), id: doc.id } as RoadmapRecord));
    } catch (e) { return []; }
  }
};

import React, { useState, useEffect } from 'react';
import { Page, User } from './types';
import Layout from './components/Layout';
import Home from './pages/Home';
import MentorChat from './pages/MentorChat';
import SkillFinder from './pages/SkillFinder';
import Roadmaps from './pages/Roadmaps';
import DailyBoost from './pages/DailyBoost';
import ProfileEntry from './pages/ProfileEntry';
import PreparingRoadmap from './pages/PreparingRoadmap';
import AdminDashboard from './pages/AdminDashboard';
import AdminReport from './pages/AdminReport';
import AdminWeeklyReport from './pages/AdminWeeklyReport';
import AdminMonthlyReport from './pages/AdminMonthlyReport';
import { authService } from './services/authService';
import { dbService } from './services/dbService';

export const ProgressRing = ({ size = "w-12 h-12" }: { size?: string }) => (
  <div className={`relative ${size} flex items-center justify-center`}>
    <svg className="w-full h-full animate-spin" viewBox="0 0 50 50">
      <circle className="opacity-10" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" />
      <circle className="text-blue-500" cx="25" cy="25" r="20" fill="none" stroke="currentColor" strokeWidth="2" strokeDasharray="80" strokeDashoffset="60" strokeLinecap="round" />
    </svg>
    <div className="absolute inset-0 bg-blue-500/5 rounded-full blur-xl"></div>
  </div>
);

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [isLoaded, setIsLoaded] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [authRedirectMessage, setAuthRedirectMessage] = useState<string | null>(null);

  useEffect(() => {
    // 1. Restore user from session immediately for UI speed
    const cachedUser = authService.getCurrentUser();
    if (cachedUser) setUser(cachedUser);

    // 2. Setup standard Auth listener
    const unsubscribe = authService.onAuthUpdate(async (fbUser) => {
      if (fbUser) {
        // Logged in: Fetch or Sync Profile
        try {
          const profile = await dbService.getUserProfile(fbUser.uid);
          if (profile) {
            setUser(profile);
            localStorage.setItem('skillshift_current_user', JSON.stringify(profile));
          } else {
            // Backup: If user is authed but no DB record, create one
            const newProfile = await dbService.createProfile(
              fbUser.uid, 
              fbUser.displayName || "User", 
              "", 
              "Other"
            );
            setUser(newProfile);
            localStorage.setItem('skillshift_current_user', JSON.stringify(newProfile));
          }
        } catch (err) {
          console.error("Auth sync error:", err);
        }
      } else {
        // Logged out
        setUser(null);
        localStorage.removeItem('skillshift_current_user');
      }
      setIsLoaded(true);
    });

    // 3. Handle Google Redirect completion (if any)
    authService.handleRedirectResult().then(u => {
      if (u) setUser(u);
    });

    // Admin detection
    const path = window.location.pathname;
    if (path.includes('admin-overview')) setCurrentPage(Page.ADMIN_DASHBOARD);
    if (path.includes('admin-daily-report')) setCurrentPage(Page.ADMIN_REPORT);

    return () => unsubscribe();
  }, []); 

  const handlePageChange = (page: Page, message?: string) => {
    if (page === Page.ROADMAPS && !user) {
      setAuthRedirectMessage(message || "Roadmap dekhne ke liye login karein.");
      setCurrentPage(Page.PROFILE_ENTRY);
      return;
    }
    if (page !== Page.PROFILE_ENTRY) setAuthRedirectMessage(null);
    setCurrentPage(page);
  };

  const handleLogout = async () => {
    await authService.logout();
    setUser(null);
    setCurrentPage(Page.HOME);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <Home onNavigate={handlePageChange} user={user} />;
      case Page.MENTOR: return <MentorChat />;
      case Page.FINDER: return <SkillFinder />;
      case Page.ROADMAPS: return <Roadmaps user={user} onAuthRequired={(msg) => handlePageChange(Page.PROFILE_ENTRY, msg)} />;
      case Page.BOOST: return <DailyBoost />;
      case Page.PROFILE_ENTRY:
        return (
          <ProfileEntry 
            redirectMessage={authRedirectMessage}
            onSuccess={(u) => {
              setUser(u);
              setAuthRedirectMessage(null);
              setCurrentPage(Page.PREPARING);
            }} 
            onBack={() => handlePageChange(Page.HOME)} 
          />
        );
      case Page.PREPARING:
        return user ? (
          <PreparingRoadmap user={user} onComplete={() => setCurrentPage(Page.ROADMAPS)} />
        ) : <Home onNavigate={handlePageChange} user={null} />;
      case Page.ADMIN_DASHBOARD: return <AdminDashboard user={user} />;
      case Page.ADMIN_REPORT: return <AdminReport user={user} />;
      case Page.ADMIN_WEEKLY_REPORT: return <AdminWeeklyReport user={user} />;
      case Page.ADMIN_MONTHLY_REPORT: return <AdminMonthlyReport user={user} />;
      default: return <Home onNavigate={handlePageChange} user={user} />;
    }
  };

  if (!isLoaded) {
    return (
      <div className="fixed inset-0 bg-slate-950 flex flex-col items-center justify-center z-[100]">
        <ProgressRing size="w-16 h-16" />
        <h1 className="mt-6 text-2xl font-bold font-heading text-white">SkillShift</h1>
      </div>
    );
  }

  return (
    <Layout currentPage={currentPage} onPageChange={handlePageChange} user={user} onLogout={handleLogout}>
      {renderPage()}
    </Layout>
  );
};

export default App;

import { 
  signInWithRedirect,
  getRedirectResult,
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from "firebase/auth";
import { auth, googleProvider } from "../firebase";
import { User, Gender } from "../types";
import { dbService } from "./dbService";

const SESSION_KEY = 'skillshift_current_user';

export const authService = {
  loginWithGoogle: async (): Promise<void> => {
    try {
      await signInWithRedirect(auth, googleProvider);
    } catch (error: any) {
      console.error("Google Auth Error:", error);
      throw error;
    }
  },

  handleRedirectResult: async (): Promise<User | null> => {
    try {
      const result = await getRedirectResult(auth);
      if (result) {
        const fbUser = result.user;
        const user = await dbService.createProfile(
          fbUser.uid,
          fbUser.displayName || "User", 
          fbUser.phoneNumber || "", 
          'Other'
        );
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        return user;
      }
      return null;
    } catch (error: any) {
      console.error("Redirect Error:", error);
      return null;
    }
  },

  signUpWithEmail: async (email: string, pass: string, name: string, gender: Gender, phone: string): Promise<User> => {
    const result = await createUserWithEmailAndPassword(auth, email, pass);
    const user = await dbService.createProfile(result.user.uid, name, phone, gender);
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  signInWithEmail: async (email: string, pass: string): Promise<User> => {
    const result = await signInWithEmailAndPassword(auth, email, pass);
    const profile = await dbService.getUserProfile(result.user.uid);
    if (!profile) throw new Error("Profile not found in database.");
    localStorage.setItem(SESSION_KEY, JSON.stringify(profile));
    return profile;
  },

  logout: async () => {
    await signOut(auth);
    localStorage.removeItem(SESSION_KEY);
  },

  getCurrentUser: (): User | null => {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  onAuthUpdate: (callback: (user: FirebaseUser | null) => void) => {
    return onAuthStateChanged(auth, callback);
  }
};

